import { Server, Socket } from 'socket.io';

interface RoomMember { userId: string; socketIds: Set<string>; }

export class RoomRegistry {
  private rooms = new Map<string, Map<string, RoomMember>>();

  join(roomId: string, userId: string, socketId: string): void {
    let room = this.rooms.get(roomId);
    if (!room) { room = new Map(); this.rooms.set(roomId, room); }
    let member = room.get(userId);
    if (!member) { member = { userId, socketIds: new Set() }; room.set(userId, member); }
    member.socketIds.add(socketId);
  }

  leave(roomId: string, userId: string, socketId: string): boolean {
    const room = this.rooms.get(roomId);
    if (!room) return false;
    const member = room.get(userId);
    if (!member) return false;
    member.socketIds.delete(socketId);
    if (member.socketIds.size === 0) {
      room.delete(userId);
      if (room.size === 0) this.rooms.delete(roomId);
      return true;
    }
    return false;
  }

  members(roomId: string): readonly string[] {
    const room = this.rooms.get(roomId);
    return room ? Array.from(room.keys()) : [];
  }
}

export function attachRoomLifecycle(io: Server, registry: RoomRegistry): void {
  io.on('connection', (socket: Socket) => {
    const userId = (socket.data as { userId?: string }).userId;
    if (!userId) { socket.disconnect(true); return; }

    socket.on('room:join', (roomId: string, ack: (ok: boolean) => void) => {
      socket.join(roomId);
      registry.join(roomId, userId, socket.id);
      ack(true);
    });

    socket.on('disconnecting', () => {
      for (const roomId of socket.rooms) {
        if (roomId === socket.id) continue;
        const lastSocket = registry.leave(roomId, userId, socket.id);
        if (lastSocket) io.to(roomId).emit('member:left', { userId });
      }
    });
  });
}

import { Socket } from 'socket.io';

interface TelemetryFrame { seq: number; ts: number; payload: unknown; }
interface SocketState { latest: TelemetryFrame | null; inFlight: boolean; dropped: number; }
const socketState = new WeakMap<Socket, SocketState>();

export function registerTelemetrySocket(socket: Socket): void {
  socketState.set(socket, { latest: null, inFlight: false, dropped: 0 });
  socket.conn.on('drain', () => flushLatest(socket));
  socket.on('disconnect', () => socketState.delete(socket));
}

export function emitTelemetry(socket: Socket, frame: TelemetryFrame): void {
  const state = socketState.get(socket);
  if (!state) return;
  state.latest = frame;
  if (state.inFlight || socket.conn.transport.writable === false) {
    state.dropped += 1;
    socket.volatile.compress(false).emit('telemetry:skipped', { latestSeq: frame.seq, dropped: state.dropped });
    return;
  }
  flushLatest(socket);
}

function flushLatest(socket: Socket): void {
  const state = socketState.get(socket);
  if (!state?.latest || socket.conn.transport.writable === false) return;
  const frame = state.latest;
  state.latest = null;
  state.inFlight = true;
  socket.volatile.compress(false).emit('telemetry:snapshot', { frame, dropped: state.dropped }, () => {
    state.inFlight = false;
    state.dropped = 0;
    if (state.latest) flushLatest(socket);
  });
}

import { Server } from 'socket.io';
import { createAdapter } from '@socket.io/redis-adapter';
import { createClient } from 'redis';
import type { Server as HttpServer } from 'http';

export async function createScalableIO(httpServer: HttpServer): Promise<Server> {
  const pubClient = createClient({ url: process.env.REDIS_URL });
  const subClient = pubClient.duplicate();
  await Promise.all([pubClient.connect(), subClient.connect()]);

  const io = new Server(httpServer, {
    transports: ['polling', 'websocket'],
    allowUpgrades: true,
    cookie: { name: 'io', httpOnly: true, sameSite: 'lax' },
    cors: { origin: process.env.CLIENT_ORIGIN, credentials: true },
    pingInterval: 25_000,
    pingTimeout: 20_000,
  });

  io.adapter(createAdapter(pubClient, subClient));
  return io;
}

