import { useEffect, useRef, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';

type EventMap = Record<string, (...args: never[]) => void>;

interface UseSocketOptions<E extends EventMap> {
  url: string;
  auth?: () => Record<string, string>;
  events: E;
}

export function useSocket<E extends EventMap>({ url, auth, events }: UseSocketOptions<E>): { emit: <K extends string>(event: K, ...args: unknown[]) => void; connected: () => boolean; } {
  const socketRef = useRef<Socket | null>(null);
  const eventsRef = useRef(events);
  eventsRef.current = events;

  useEffect(() => {
    const socket = io(url, {
      auth: auth?.(),
      reconnection: true,
      reconnectionAttempts: Infinity,
      reconnectionDelay: 500,
      reconnectionDelayMax: 5000,
      randomizationFactor: 0.5,
    });
    socketRef.current = socket;

    const handlers: Array<[string, (...a: never[]) => void]> = [];
    for (const [event, handler] of Object.entries(eventsRef.current)) {
      const wrapped = (...args: never[]): void => handler(...args);
      socket.on(event, wrapped);
      handlers.push([event, wrapped]);
    }

    return () => {
      for (const [event, handler] of handlers) socket.off(event, handler);
      socket.disconnect();
      socketRef.current = null;
    };
  }, [url, auth]);

  const emit = useCallback(<K extends string>(event: K, ...args: unknown[]): void => {
    socketRef.current?.emit(event, ...args);
  }, []);

  const connected = useCallback((): boolean => socketRef.current?.connected ?? false, []);

  return { emit, connected };
}

import { Server, Socket } from 'socket.io';
import jwt from 'jsonwebtoken';

interface JwtPayload { sub: string; exp: number; scope: string[]; }
interface SocketAuthData { userId: string; scope: string[]; expiresAt: number; }

const SECRET = process.env.JWT_SECRET!;
const FRESHNESS_GRACE_MS = 5_000;

function verify(token: string): SocketAuthData {
  const decoded = jwt.verify(token, SECRET) as JwtPayload;
  return { userId: decoded.sub, scope: decoded.scope, expiresAt: decoded.exp * 1000 };
}

export function attachAuth(io: Server): void {
  io.use((socket, next) => {
    const token = (socket.handshake.auth as { token?: string }).token;
    if (!token) return next(new Error('UNAUTHENTICATED'));
    try {
      (socket.data as { auth: SocketAuthData }).auth = verify(token);
      next();
    } catch { next(new Error('INVALID_TOKEN')); }
  });

  io.on('connection', (socket: Socket) => {
    socket.on('auth:refresh', (token: string, ack: (ok: boolean) => void) => {
      try {
        const next = verify(token);
        (socket.data as { auth: SocketAuthData }).auth = next;
        ack(true);
      } catch { ack(false); socket.disconnect(true); }
    });
  });
}

export function requireFreshAuth<T extends unknown[]>(
  handler: (socket: Socket, ...args: T) => Promise<void> | void,
): (socket: Socket, ...args: T) => Promise<void> {
  return async (socket, ...args) => {
    const auth = (socket.data as { auth?: SocketAuthData }).auth;
    if (!auth || Date.now() > auth.expiresAt - FRESHNESS_GRACE_MS) {
      socket.emit('auth:stale');
      return;
    }
    await handler(socket, ...args);
  };
}

import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import crypto from 'crypto';

interface RefreshPayload { sub: string; jti: string; exp: number; }
interface RefreshStore { isValid(jti: string): Promise<boolean>; invalidate(jti: string): Promise<void>; getReplacement(jti: string): Promise<{ access: string; refresh: string } | null>; setReplacement(oldJti: string, tokens: { access: string; refresh: string }, ttlMs: number): Promise<void>; }

const REPLACEMENT_GRACE_MS = 30_000;
const SECRET = process.env.JWT_SECRET!;

function sign(userId: string): { access: string; refresh: string; refreshJti: string } {
  const refreshJti = crypto.randomBytes(16).toString('hex');
  return {
    access: jwt.sign({ sub: userId }, SECRET, { expiresIn: '15m' }),
    refresh: jwt.sign({ sub: userId, jti: refreshJti }, SECRET, { expiresIn: '7d' }),
    refreshJti,
  };
}

export function refreshHandler(store: RefreshStore) {
  return async (req: Request, res: Response, next: NextFunction): Promise<void> => {
    try {
      const token = (req.cookies as Record<string, string>)?.refresh;
      if (!token) { res.status(401).json({ error: 'NO_REFRESH' }); return; }
      let payload: RefreshPayload;
      try { payload = jwt.verify(token, SECRET) as RefreshPayload; }
      catch { res.status(401).json({ error: 'INVALID' }); return; }

      const valid = await store.isValid(payload.jti);
      if (!valid) {
        const replacement = await store.getReplacement(payload.jti);
        if (replacement) {
          setCookies(res, replacement);
          res.json({ accessToken: replacement.access });
          return;
        }
        await store.invalidate(payload.jti);
        res.status(401).json({ error: 'REUSED' });
        return;
      }

      const next = sign(payload.sub);
      await store.invalidate(payload.jti);
      await store.setReplacement(payload.jti, { access: next.access, refresh: next.refresh }, REPLACEMENT_GRACE_MS);
      setCookies(res, { access: next.access, refresh: next.refresh });
      res.json({ accessToken: next.access });
    } catch (e) { next(e); }
  };
}

function setCookies(res: Response, t: { access: string; refresh: string }): void {
  res.cookie('refresh', t.refresh, { httpOnly: true, secure: true, sameSite: 'strict', path: '/auth/refresh', maxAge: 7 * 24 * 3600 * 1000 });
}

import { Request, Response } from 'express';
import { z } from 'zod';
import { FilterQuery } from 'mongoose';
import { UserModel, type User } from './user.model';

const SearchDto = z.object({
  email: z.string().email().optional(),
  nameContains: z.string().min(1).max(80).optional(),
  createdAfter: z.string().datetime().optional(),
  role: z.enum(['user', 'admin', 'staff']).optional(),
  limit: z.number().int().min(1).max(100).default(20),
  cursor: z.string().regex(/^[0-9a-f]{24}$/).optional(),
}).strict();

type SearchInput = z.infer<typeof SearchDto>;

function buildFilter(input: SearchInput): FilterQuery<User> {
  const filter: FilterQuery<User> = {};
  if (input.email) filter.email = input.email.toLowerCase();
  if (input.role) filter.role = input.role;
  if (input.nameContains) {
    const escaped = input.nameContains.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    filter.name = { $regex: escaped, $options: 'i' };
  }
  if (input.createdAfter) filter.createdAt = { $gt: new Date(input.createdAfter) };
  if (input.cursor) filter._id = { $gt: input.cursor };
  return filter;
}

export async function searchUsers(req: Request, res: Response): Promise<void> {
  const parsed = SearchDto.safeParse(req.body);
  if (!parsed.success) { res.status(400).json({ errors: parsed.error.flatten() }); return; }
  const filter = buildFilter(parsed.data);
  const users = await UserModel.find(filter).select('-password -passwordResetToken').limit(parsed.data.limit).sort({ _id: 1 }).lean();
  res.json({ users, nextCursor: users.length === parsed.data.limit ? users[users.length - 1]._id : null });
}

import { Request, Response, NextFunction } from 'express';
import type { Redis } from 'ioredis';

const SCRIPT = `
local key = KEYS[1]
local window = tonumber(ARGV[1])
local limit = tonumber(ARGV[2])
local now = tonumber(ARGV[3])
local currentWindow = math.floor(now / window)
local prevWindow = currentWindow - 1
local currentKey = key .. ':' .. currentWindow
local prevKey = key .. ':' .. prevWindow
local current = tonumber(redis.call('GET', currentKey) or '0')
local previous = tonumber(redis.call('GET', prevKey) or '0')
local elapsedInWindow = now % window
local weight = (window - elapsedInWindow) / window
local estimated = math.floor(previous * weight) + current
if estimated >= limit then
  return { 0, limit - estimated, window - elapsedInWindow }
end
local newCount = redis.call('INCR', currentKey)
if newCount == 1 then redis.call('PEXPIRE', currentKey, window * 2) end
return { 1, limit - estimated - 1, window - elapsedInWindow }
`;

export interface RateLimitOptions { windowMs: number; max: number; keyFn: (req: Request) => string; }

export function rateLimit(redis: Redis, opts: RateLimitOptions) {
  return async (req: Request, res: Response, next: NextFunction): Promise<void> => {
    try {
      const key = `rl:${opts.keyFn(req)}`;
      const result = await redis.eval(SCRIPT, 1, key, String(opts.windowMs), String(opts.max), String(Date.now())) as [number, number, number];
      const [allowed, remaining, resetMs] = result;
      res.setHeader('X-RateLimit-Limit', opts.max);
      res.setHeader('X-RateLimit-Remaining', Math.max(0, remaining));
      res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));
      if (allowed === 0) { res.status(429).json({ error: 'RATE_LIMITED', retryAfter: Math.ceil(resetMs / 1000) }); return; }
      next();
    } catch (e) { next(e); }
  };
}

import express from 'express';
import cors from 'cors';
import cookieParser from 'cookie-parser';
import { Server } from 'socket.io';
import { createServer } from 'http';
import crypto from 'crypto';

const ALLOWED_ORIGINS = (process.env.ALLOWED_ORIGINS ?? '').split(',').filter(Boolean);

export function createApp() {
  const app = express();
  app.set('trust proxy', 1);
  app.use(cookieParser());
  app.use(cors({
    origin: (origin, cb) => {
      if (!origin) return cb(null, true);
      cb(null, ALLOWED_ORIGINS.includes(origin));
    },
    credentials: true,
    methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE'],
    allowedHeaders: ['Content-Type', 'X-CSRF-Token'],
    maxAge: 600,
  }));

  app.use((req, res, next) => {
    if (['GET', 'HEAD', 'OPTIONS'].includes(req.method)) return next();
    const cookieToken = (req.cookies as Record<string, string>)?.csrf;
    const headerToken = req.header('X-CSRF-Token');
    if (!cookieToken || cookieToken !== headerToken) { res.status(403).json({ error: 'CSRF' }); return; }
    next();
  });

  app.get('/auth/csrf', (_req, res) => {
    const token = crypto.randomBytes(32).toString('hex');
    res.cookie('csrf', token, { httpOnly: false, secure: true, sameSite: 'none', domain: '.example.com' });
    res.json({ csrfToken: token });
  });

  const httpServer = createServer(app);
  const io = new Server(httpServer, {
    cors: { origin: ALLOWED_ORIGINS, credentials: true },
    cookie: { name: 'io', httpOnly: true, secure: true, sameSite: 'none', domain: '.example.com' },
  });

  return { app, httpServer, io };
}

