import argon2 from 'argon2';
import { Request, Response } from 'express';
import { UserModel } from './user.model';

const DUMMY_HASH = '$argon2id$v=19$m=65536,t=3,p=4$ZHVtbXlzYWx0ZHVtbXk$AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA';
const ARGON_OPTS: argon2.Options = { type: argon2.argon2id, memoryCost: 65536, timeCost: 3, parallelism: 4 };

export async function login(req: Request, res: Response): Promise<void> {
  const { email, password } = req.body as { email?: unknown; password?: unknown };
  if (typeof email !== 'string' || typeof password !== 'string') {
    res.status(400).json({ error: 'INVALID_INPUT' });
    return;
  }

  const user = await UserModel.findOne({ email: email.toLowerCase() }).select('+passwordHash').lean();
  const hashToVerify = user?.passwordHash ?? DUMMY_HASH;
  let valid = false;
  try {
    valid = await argon2.verify(hashToVerify, password, ARGON_OPTS);
  } catch { valid = false; }

  if (!user || !valid) {
    res.status(401).json({ error: 'INVALID_CREDENTIALS' });
    return;
  }

  if (await argon2.needsRehash(user.passwordHash, ARGON_OPTS)) {
    const newHash = await argon2.hash(password, ARGON_OPTS);
    await UserModel.updateOne({ _id: user._id }, { passwordHash: newHash });
  }

  res.json({ accessToken: await createAccessToken(user._id) });
}

import { createContext, useContext, useRef, useCallback, useSyncExternalStore, ReactNode } from 'react';

type Listener<T> = (state: T) => void;
interface Store<T> { get: () => T; set: (updater: (s: T) => T) => void; subscribe: (l: Listener<T>) => () => void; }

export function createStore<T>(initial: T): Store<T> {
  let state = initial;
  const listeners = new Set<Listener<T>>();
  return {
    get: () => state,
    set: (updater) => { state = updater(state); listeners.forEach((l) => l(state)); },
    subscribe: (l) => { listeners.add(l); return () => { listeners.delete(l); }; },
  };
}

export function createStoreContext<T>(initial: T) {
  const Ctx = createContext<Store<T> | null>(null);

  function Provider({ children, initialValue }: { children: ReactNode; initialValue?: T }) {
    const storeRef = useRef<Store<T> | null>(null);
    if (!storeRef.current) storeRef.current = createStore(initialValue ?? initial);
    return <Ctx.Provider value={storeRef.current}>{children}</Ctx.Provider>;
  }

  function useStore<S>(selector: (s: T) => S, isEqual: (a: S, b: S) => boolean = Object.is): S {
    const store = useContext(Ctx);
    if (!store) throw new Error('Provider missing');
    const lastSnapshot = useRef<{ state: T; selected: S } | null>(null);
    const getSnapshot = useCallback((): S => {
      const state = store.get();
      const last = lastSnapshot.current;
      if (last && last.state === state) return last.selected;
      const selected = selector(state);
      if (last && isEqual(last.selected, selected)) {
        lastSnapshot.current = { state, selected: last.selected };
        return last.selected;
      }
      lastSnapshot.current = { state, selected };
      return selected;
    }, [store, selector, isEqual]);
    return useSyncExternalStore(store.subscribe, getSnapshot, getSnapshot);
  }

  function useSet(): Store<T>['set'] {
    const store = useContext(Ctx);
    if (!store) throw new Error('Provider missing');
    return store.set;
  }

  return { Provider, useStore, useSet };
}

import { useState, useCallback, useRef } from 'react';

interface OptimisticState { value: number; inflightDelta: number; }

interface UseOptimisticCounterArgs { initial: number; mutate: (delta: number) => Promise<{ value: number }>; }

export function useOptimisticCounter({ initial, mutate }: UseOptimisticCounterArgs) {
  const [state, setState] = useState<OptimisticState>({ value: initial, inflightDelta: 0 });
  const generationRef = useRef(0);

  const apply = useCallback(async (delta: number): Promise<void> => {
    const gen = ++generationRef.current;
    setState((s) => ({ value: s.value + delta, inflightDelta: s.inflightDelta + delta }));
    try {
      const { value: serverValue } = await mutate(delta);
      setState((s) => {
        if (gen !== generationRef.current) return { ...s, inflightDelta: s.inflightDelta - delta };
        return { value: serverValue, inflightDelta: 0 };
      });
    } catch {
      setState((s) => ({ value: s.value - delta, inflightDelta: s.inflightDelta - delta }));
    }
  }, [mutate]);

  return { value: state.value, increment: () => apply(1), decrement: () => apply(-1) };
}

import { useEffect, useRef, useLayoutEffect, useCallback } from 'react';

export function useEvent<T extends (...args: never[]) => unknown>(handler: T): T {
  const ref = useRef<T>(handler);
  useLayoutEffect(() => { ref.current = handler; });
  return useCallback(((...args: Parameters<T>) => ref.current(...args)) as T, []);
}

import { Socket } from 'socket.io-client';

interface UseLiveCounterArgs { socket: Socket; topic: string; onUpdate: (next: number) => void; }

export function useLiveCounter({ socket, topic, onUpdate }: UseLiveCounterArgs): void {
  const stableOnUpdate = useEvent(onUpdate);
  useEffect(() => {
    const handler = (payload: { topic: string; value: number }): void => {
      if (payload.topic !== topic) return;
      stableOnUpdate(payload.value);
    };
    socket.on('counter:update', handler);
    return () => { socket.off('counter:update', handler); };
  }, [socket, topic, stableOnUpdate]);
}

import { useEffect, useRef, useState } from 'react';

interface SearchResult<T> { data: T | null; error: Error | null; loading: boolean; }

export function useDebouncedSearch<T>(
  query: string,
  fetcher: (q: string, signal: AbortSignal) => Promise<T>,
  debounceMs = 250,
): SearchResult<T> {
  const [state, setState] = useState<SearchResult<T>>({ data: null, error: null, loading: false });
  const generationRef = useRef(0);

  useEffect(() => {
    if (query.trim().length === 0) { setState({ data: null, error: null, loading: false }); return; }

    const controller = new AbortController();
    const gen = ++generationRef.current;
    let timer: ReturnType<typeof setTimeout> | null = null;

    setState((s) => ({ ...s, loading: true }));

    timer = setTimeout(async () => {
      try {
        const data = await fetcher(query, controller.signal);
        if (gen !== generationRef.current || controller.signal.aborted) return;
        setState({ data, error: null, loading: false });
      } catch (err) {
        if (gen !== generationRef.current || controller.signal.aborted) return;
        if (err instanceof DOMException && err.name === 'AbortError') return;
        setState({ data: null, error: err as Error, loading: false });
      }
    }, debounceMs);

    return () => {
      if (timer) clearTimeout(timer);
      controller.abort();
    };
  }, [query, fetcher, debounceMs]);

  return state;
}

import { useCallback, useEffect, useReducer, useRef, useState } from 'react';

type State<T, E = Error> =
  | { status: 'idle' }
  | { status: 'loading' }
  | { status: 'success'; data: T }
  | { status: 'error'; error: E };

type Action<T, E = Error> =
  | { type: 'FETCH' }
  | { type: 'SUCCESS'; data: T }
  | { type: 'ERROR'; error: E }
  | { type: 'RESET' };

function reducer<T, E>(_state: State<T, E>, action: Action<T, E>): State<T, E> {
  switch (action.type) {
    case 'FETCH': return { status: 'loading' };
    case 'SUCCESS': return { status: 'success', data: action.data };
    case 'ERROR': return { status: 'error', error: action.error };
    case 'RESET': return { status: 'idle' };
  }
}

export function useAsyncResource<T>(
  fetcher: (signal: AbortSignal) => Promise<T>,
  deps: readonly unknown[] = [],
): State<T> & { reload: () => void; reset: () => void } {
  const [state, dispatch] = useReducer(reducer<T, Error>, { status: 'idle' });
  const [reloadVersion, setReloadVersion] = useState(0);
  const fetcherRef = useRef(fetcher);
  fetcherRef.current = fetcher;

  const reload = useCallback(() => setReloadVersion((v) => v + 1), []);
  const reset = useCallback(() => dispatch({ type: 'RESET' }), []);

  useEffect(() => {
    const controller = new AbortController();
    let active = true;

    dispatch({ type: 'FETCH' });
    fetcherRef.current(controller.signal)
      .then((data) => {
        if (active && !controller.signal.aborted) dispatch({ type: 'SUCCESS', data });
      })
      .catch((err: unknown) => {
        if (!active || controller.signal.aborted) return;
        dispatch({ type: 'ERROR', error: err instanceof Error ? err : new Error(String(err)) });
      });

    return () => {
      active = false;
      controller.abort();
    };
  }, [reloadVersion, ...deps]);

  return { ...state, reload, reset };
}

import { useMemo, useEffect, useRef } from 'react';
import * as THREE from 'three';
import { useFrame } from '@react-three/fiber';

interface DynamicMeshProps { width: number; height: number; segments: number; color: string; }

export function DynamicMesh({ width, height, segments, color }: DynamicMeshProps) {
  const geometry = useMemo(() => new THREE.PlaneGeometry(width, height, segments, segments), [width, height, segments]);
  const material = useMemo(() => new THREE.MeshStandardMaterial({ color }), [color]);
  const meshRef = useRef<THREE.Mesh>(null);

  useEffect(() => () => { geometry.dispose(); }, [geometry]);
  useEffect(() => () => { material.dispose(); }, [material]);

  useFrame((_, dt) => { if (meshRef.current) meshRef.current.rotation.y += dt * 0.5; });

  return <mesh ref={meshRef} geometry={geometry} material={material} />;
}

export function disposeObject(obj: THREE.Object3D): void {
  obj.traverse((node) => {
    if ((node as THREE.Mesh).isMesh) {
      const mesh = node as THREE.Mesh;
      mesh.geometry.dispose();
      const materials = Array.isArray(mesh.material) ? mesh.material : [mesh.material];
      for (const mat of materials) {
        for (const key of Object.keys(mat)) {
          const value = (mat as unknown as Record<string, unknown>)[key];
          if (value instanceof THREE.Texture) value.dispose();
        }
        mat.dispose();
      }
    }
  });
}

import { useLoader } from '@react-three/fiber';
import { TextureLoader } from 'three';

export function TexturedQuad({ url }: { url: string }) {
  const texture = useLoader(TextureLoader, url);
  useEffect(() => () => { texture.dispose(); }, [texture]);
  return (
    <mesh>
      <planeGeometry args={[1, 1]} />
      <meshBasicMaterial map={texture} />
    </mesh>
  );
}

import { useRef, useMemo, useEffect } from 'react';
import * as THREE from 'three';
import { useFrame } from '@react-three/fiber';

interface ForestProps { positions: ReadonlyArray<readonly [number, number, number]>; geometry: THREE.BufferGeometry; material: THREE.Material; }

export function InstancedForest({ positions, geometry, material }: ForestProps) {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const dummy = useMemo(() => new THREE.Object3D(), []);
  const colorArray = useMemo(() => new Float32Array(positions.length * 3), [positions.length]);

  useEffect(() => {
    if (!meshRef.current) return;
    for (let i = 0; i < positions.length; i++) {
      const [x, y, z] = positions[i];
      dummy.position.set(x, y, z);
      dummy.rotation.y = (i * 137.5) % (Math.PI * 2);
      const scale = 0.8 + ((i * 23) % 100) / 250;
      dummy.scale.setScalar(scale);
      dummy.updateMatrix();
      meshRef.current.setMatrixAt(i, dummy.matrix);
      const greenVariation = 0.4 + ((i * 17) % 100) / 200;
      colorArray[i * 3] = 0.1;
      colorArray[i * 3 + 1] = greenVariation;
      colorArray[i * 3 + 2] = 0.1;
    }
    meshRef.current.instanceMatrix.needsUpdate = true;
    meshRef.current.instanceColor = new THREE.InstancedBufferAttribute(colorArray, 3);
    meshRef.current.instanceColor.needsUpdate = true;
  }, [positions, dummy, colorArray]);

  useFrame(({ clock }) => {
    if (!meshRef.current) return;
    meshRef.current.rotation.y = clock.elapsedTime * 0.02;
  });

  return <instancedMesh ref={meshRef} args={[geometry, material, positions.length]} frustumCulled={false} castShadow receiveShadow />;
}

import { useEffect, useRef } from 'react';
import * as THREE from 'three';

export function useThreeCanvas(setup: (renderer: THREE.WebGLRenderer, scene: THREE.Scene, camera: THREE.PerspectiveCamera) => () => void) {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true, powerPreference: 'high-performance' });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(60, 1, 0.1, 1000);
    container.appendChild(renderer.domElement);
    renderer.domElement.style.width = '100%';
    renderer.domElement.style.height = '100%';
    renderer.domElement.style.display = 'block';

    const cleanup = setup(renderer, scene, camera);

    const ro = new ResizeObserver((entries) => {
      for (const entry of entries) {
        const { width, height } = entry.contentRect;
        if (width === 0 || height === 0) continue;
        renderer.setSize(width, height, false);
        camera.aspect = width / height;
        camera.updateProjectionMatrix();
      }
    });
    ro.observe(container);

    const onContextLost = (e: Event): void => { e.preventDefault(); };
    renderer.domElement.addEventListener('webglcontextlost', onContextLost);

    return () => {
      ro.disconnect();
      cleanup();
      renderer.domElement.removeEventListener('webglcontextlost', onContextLost);
      renderer.dispose();
      renderer.forceContextLoss();
      if (renderer.domElement.parentNode) renderer.domElement.parentNode.removeChild(renderer.domElement);
    };
  }, [setup]);

  return containerRef;
}

import { Request, Response, NextFunction, ErrorRequestHandler, RequestHandler } from 'express';
import { ZodError } from 'zod';

export abstract class AppError extends Error {
  abstract readonly statusCode: number;
  abstract readonly code: string;
  readonly isOperational = true;
  constructor(message: string, public readonly details?: unknown) {
    super(message);
    this.name = this.constructor.name;
    Error.captureStackTrace?.(this, this.constructor);
  }
}

export class ValidationError extends AppError { readonly statusCode = 400; readonly code = 'VALIDATION_ERROR'; }
export class UnauthenticatedError extends AppError { readonly statusCode = 401; readonly code = 'UNAUTHENTICATED'; }
export class ForbiddenError extends AppError { readonly statusCode = 403; readonly code = 'FORBIDDEN'; }
export class NotFoundError extends AppError { readonly statusCode = 404; readonly code = 'NOT_FOUND'; }
export class ConflictError extends AppError { readonly statusCode = 409; readonly code = 'CONFLICT'; }
export class RateLimitError extends AppError { readonly statusCode = 429; readonly code = 'RATE_LIMITED'; }

export function asyncHandler<P, ResBody, ReqBody, Q>(
  fn: (req: Request<P, ResBody, ReqBody, Q>, res: Response<ResBody>, next: NextFunction) => Promise<unknown>,
): RequestHandler<P, ResBody, ReqBody, Q> {
  return (req, res, next) => { Promise.resolve(fn(req, res, next)).catch(next); };
}

interface Logger { error(msg: string, ctx: Record<string, unknown>): void; }

export function errorMiddleware(logger: Logger): ErrorRequestHandler {
  return (err, req, res, _next) => {
    if (err instanceof ZodError) {
      res.status(400).json({ error: { code: 'VALIDATION_ERROR', message: 'Invalid input', details: err.flatten() } });
      return;
    }
    if (err instanceof AppError) {
      res.status(err.statusCode).json({ error: { code: err.code, message: err.message, details: err.details } });
      return;
    }
    const error = err as Error;
    logger.error('Unhandled error', { name: error.name, message: error.message, stack: error.stack, path: req.path, method: req.method });
    res.status(500).json({ error: { code: 'INTERNAL', message: 'An unexpected error occurred' } });
  };
}

export interface RetryOptions { maxAttempts: number; baseDelayMs: number; maxDelayMs: number; retryOn?: (err: unknown) => boolean; }

export async function withRetry<T>(fn: () => Promise<T>, opts: RetryOptions): Promise<T> {
  let lastErr: unknown;
  for (let attempt = 1; attempt <= opts.maxAttempts; attempt++) {
    try { return await fn(); }
    catch (err) {
      lastErr = err;
      if (opts.retryOn && !opts.retryOn(err)) throw err;
      if (attempt === opts.maxAttempts) break;
      const exp = Math.min(opts.maxDelayMs, opts.baseDelayMs * 2 ** (attempt - 1));
      const jitter = Math.random() * exp;
      await new Promise((r) => setTimeout(r, jitter));
    }
  }
  throw lastErr;
}

type CircuitState = 'closed' | 'open' | 'half-open';

export interface BreakerOptions { failureThreshold: number; cooldownMs: number; }

export class CircuitBreaker {
  private state: CircuitState = 'closed';
  private failures = 0;
  private openedAt = 0;
  constructor(private readonly opts: BreakerOptions) {}

  async exec<T>(fn: () => Promise<T>): Promise<T> {
    if (this.state === 'open') {
      if (Date.now() - this.openedAt < this.opts.cooldownMs) throw new Error('CIRCUIT_OPEN');
      this.state = 'half-open';
    }
    try {
      const result = await fn();
      this.failures = 0;
      this.state = 'closed';
      return result;
    } catch (err) {
      this.failures++;
      if (this.state === 'half-open' || this.failures >= this.opts.failureThreshold) {
        this.state = 'open';
        this.openedAt = Date.now();
      }
      throw err;
    }
  }
}

