import { ConflictError, NotFoundError } from '../errors';

export interface InventoryService { reserve(items: Array<{ sku: string; qty: number }>): Promise<{ ok: boolean; missing: string[] }>; }
export interface PricingService { priceItems(items: Array<{ sku: string; qty: number }>): Promise<Array<{ sku: string; qty: number; priceCents: number }>>; }

export class OrderService {
  constructor(private readonly orders: OrderDal, private readonly inventory: InventoryService, private readonly pricing: PricingService) {}

  async create(userId: string, items: Array<{ sku: string; qty: number }>): Promise<OrderDoc> {
    const reservation = await this.inventory.reserve(items);
    if (!reservation.ok) throw new ConflictError('Out of stock', { missing: reservation.missing });
    const priced = await this.pricing.priceItems(items);
    return this.orders.create({ userId, items: priced });
  }

  async get(id: string): Promise<OrderDoc> {
    const order = await this.orders.findById(id);
    if (!order) throw new NotFoundError('Order not found');
    return order;
  }
}

