import { Types } from 'mongoose';
import { OrderModel } from './order.model';

interface OrderListItem { _id: string; userId: string; userName: string; userEmail: string; total: number; createdAt: Date; }

export interface ListOrdersFilter { userId?: string; status?: 'pending' | 'paid' | 'shipped'; createdAfter?: Date; }

export async function listOrdersWithUser(filter: ListOrdersFilter, limit = 100): Promise<OrderListItem[]> {
  const match: Record<string, unknown> = {};
  if (filter.userId) match.userId = new Types.ObjectId(filter.userId);
  if (filter.status) match.status = filter.status;
  if (filter.createdAfter) match.createdAt = { $gt: filter.createdAfter };

  const results = await OrderModel.aggregate<{ _id: Types.ObjectId; userId: Types.ObjectId; user: { name: string; email: string }; total: number; createdAt: Date; }>([
    { $match: match },
    { $sort: { createdAt: -1 } },
    { $limit: limit },
    { $lookup: { from: 'users', localField: 'userId', foreignField: '_id', as: 'user', pipeline: [{ $project: { name: 1, email: 1 } }] } },
    { $unwind: { path: '$user', preserveNullAndEmptyArrays: true } },
    { $project: { _id: 1, userId: 1, user: 1, createdAt: 1, total: { $sum: { $map: { input: '$items', as: 'i', in: { $multiply: ['$$i.qty', '$$i.priceCents'] } } } } } },
  ]).exec();

  return results.map((r) => ({ _id: String(r._id), userId: String(r.userId), userName: r.user?.name ?? '(deleted)', userEmail: r.user?.email ?? '', total: r.total, createdAt: r.createdAt }));
}

import { Schema, model } from 'mongoose';

interface Product { _id: string; name: string; priceCents: number; stockQty: number; __v: number; updatedAt: Date; }

const ProductSchema = new Schema<Product>({
  name: { type: String, required: true },
  priceCents: { type: Number, required: true, min: 0 },
  stockQty: { type: Number, required: true, min: 0 },
}, { timestamps: { createdAt: false, updatedAt: true }, optimisticConcurrency: true });

export const ProductModel = model<Product>('Product', ProductSchema);

import { ConflictError, NotFoundError } from '../errors';

export interface ProductUpdate { name?: string; priceCents?: number; stockQty?: number; }

export class ProductService {
  async update(id: string, expectedVersion: number, patch: ProductUpdate): Promise<Product> {
    const result = await ProductModel.findOneAndUpdate(
      { _id: id, __v: expectedVersion },
      { $set: patch, $inc: { __v: 1 } },
      { new: true, lean: true },
    );
    if (!result) {
      const current = await ProductModel.findById(id).lean<Product | null>();
      if (!current) throw new NotFoundError('Product');
      throw new ConflictError('Concurrent edit detected', { current, expectedVersion, actualVersion: current.__v });
    }
    return result;
  }
}

import { z, ZodType } from 'zod';

type Method = 'GET' | 'POST' | 'PUT' | 'PATCH' | 'DELETE';

type RouteKey = `${Method} ${string}`;

export interface RouteSpec<TBody extends ZodType | undefined, TResponse extends ZodType> {
  method: Method;
  path: `/${string}`;
  body?: TBody;
  response: TResponse;
}

export type RouteMap = Record<RouteKey, RouteSpec<ZodType | undefined, ZodType>>;

type BodyOf<R extends RouteSpec<ZodType | undefined, ZodType>> =
  R['body'] extends ZodType ? z.infer<R['body']> : undefined;

type ResponseOf<R extends RouteSpec<ZodType | undefined, ZodType>> = z.infer<R['response']>;

export class TypedClient<M extends RouteMap> {
  constructor(private readonly baseUrl: string, private readonly routes: M) {}

  async call<K extends keyof M & string>(
    routeKey: K,
    ...args: BodyOf<M[K]> extends undefined
      ? [init?: { signal?: AbortSignal; headers?: Record<string, string> }]
      : [body: BodyOf<M[K]>, init?: { signal?: AbortSignal; headers?: Record<string, string> }]
  ): Promise<ResponseOf<M[K]>> {
    const route = this.routes[routeKey];
    const [maybeBody, maybeInit] = route.body
      ? args
      : [undefined, args[0] as { signal?: AbortSignal; headers?: Record<string, string> } | undefined];

    const res = await fetch(this.baseUrl + route.path, {
      method: route.method,
      headers: { 'Content-Type': 'application/json', ...maybeInit?.headers },
      body: maybeBody === undefined ? undefined : JSON.stringify(maybeBody),
      signal: maybeInit?.signal,
    });
    if (!res.ok) throw new Error(`HTTP_${res.status}`);
    return route.response.parse(await res.json()) as ResponseOf<M[K]>;
  }
}

