import { Server } from 'socket.io';
import type { ServerToClientEvents, ClientToServerEvents, InterServerEvents, SocketData } from './shared/events';

export function buildIO(httpServer: import('http').Server) {
  const io = new Server<ClientToServerEvents, ServerToClientEvents, InterServerEvents, SocketData>(httpServer);
  io.on('connection', (socket) => {
    socket.on('chat:send', (text, ack) => {
      if (text.length === 0 || text.length > 2000) { ack({ ok: false, error: 'INVALID' }); return; }
      const id = crypto.randomUUID();
      io.emit('chat:message', { id, from: socket.data.userId, text, ts: Date.now() });
      ack({ ok: true, id });
    });
  });
  return io;
}

