import { Socket } from 'socket.io';

interface AuthData { userId: string; roles: ReadonlyArray<'user' | 'admin' | 'staff'>; }

type Handler<A extends unknown[]> = (socket: Socket, ...args: A) => Promise<void> | void;
type Guard = (socket: Socket) => { ok: true } | { ok: false; code: string; message: string };

export const requireAuth: Guard = (socket) => {
  const auth = (socket.data as { auth?: AuthData }).auth;
  return auth ? { ok: true } : { ok: false, code: 'UNAUTHENTICATED', message: 'Login required' };
};

export const requireRole = (role: 'admin' | 'staff'): Guard => (socket) => {
  const auth = (socket.data as { auth?: AuthData }).auth;
  if (!auth) return { ok: false, code: 'UNAUTHENTICATED', message: 'Login required' };
  return auth.roles.includes(role) ? { ok: true } : { ok: false, code: 'FORBIDDEN', message: `Role ${role} required` };
};

export function compose<A extends unknown[]>(guards: Guard[], handler: Handler<A>): Handler<A> {
  return async (socket, ...args) => {
    for (const guard of guards) {
      const result = guard(socket);
      if (!result.ok) { socket.emit('error', { code: result.code, message: result.message }); return; }
    }
    await handler(socket, ...args);
  };
}

