import { Socket } from 'socket.io';

interface IdempotencyStore {
  get(key: string): Promise<{ result: unknown } | null>;
  setIfAbsent(key: string, result: unknown, ttlMs: number): Promise<boolean>;
}

export function idempotent<Req, Res>(
  store: IdempotencyStore,
  ttlMs: number,
  handler: (socket: Socket, req: Req) => Promise<Res>,
) {
  return async (socket: Socket, req: Req & { requestId: string }, ack: (res: Res | { error: string }) => void): Promise<void> => {
    if (!req?.requestId || typeof req.requestId !== 'string') { ack({ error: 'MISSING_REQUEST_ID' }); return; }
    const key = `${socket.data.userId}:${req.requestId}`;
    const existing = await store.get(key);
    if (existing) { ack(existing.result as Res); return; }
    const result = await handler(socket, req);
    await store.setIfAbsent(key, result, ttlMs);
    ack(result);
  };
}

