import { useEffect, useState } from 'react';
import type { Socket } from 'socket.io-client';

export type ConnectionState = 'connecting' | 'connected' | 'reconnecting' | 'offline';

export function useConnectionState(socket: Socket): ConnectionState {
  const [state, setState] = useState<ConnectionState>(socket.connected ? 'connected' : 'connecting');

  useEffect(() => {
    const onConnect = (): void => setState('connected');
    const onDisconnect = (reason: Socket.DisconnectReason): void => {
      setState(reason === 'io server disconnect' || reason === 'io client disconnect' ? 'offline' : 'reconnecting');
    };
    const onReconnectAttempt = (): void => setState('reconnecting');
    const onReconnectFailed = (): void => setState('offline');

    socket.on('connect', onConnect);
    socket.on('disconnect', onDisconnect);
    socket.io.on('reconnect_attempt', onReconnectAttempt);
    socket.io.on('reconnect_failed', onReconnectFailed);

    return () => {
      socket.off('connect', onConnect);
      socket.off('disconnect', onDisconnect);
      socket.io.off('reconnect_attempt', onReconnectAttempt);
      socket.io.off('reconnect_failed', onReconnectFailed);
    };
  }, [socket]);

  return state;
}

import { Server as IOServer } from 'socket.io';
import { Server as HttpServer } from 'http';

export function attachGracefulShutdown(httpServer: HttpServer, io: IOServer, opts: { drainMs: number; timeoutMs: number }): void {
  let shuttingDown = false;

  const shutdown = async (signal: NodeJS.Signals): Promise<void> => {
    if (shuttingDown) return;
    shuttingDown = true;
    reporter.write(`[shutdown] received ${signal}`);

    httpServer.close((err) => {
      if (err) console.error('[shutdown] http close error', err);
    });

    io.emit('server:shutdown', { reconnectAfterMs: 1000 });

    await new Promise((r) => setTimeout(r, opts.drainMs));

    const closePromise = new Promise<void>((resolve) => { io.close(() => resolve()); });
    const timeoutPromise = new Promise<void>((resolve) => setTimeout(resolve, opts.timeoutMs));
    await Promise.race([closePromise, timeoutPromise]);

    process.exit(0);
  };

  process.on('SIGTERM', shutdown);
  process.on('SIGINT', shutdown);
}

import { useEffect, useRef } from 'react';
import type { Socket } from 'socket.io-client';

type ResyncResponse<T> = { type: 'delta'; events: Array<{ seq: number; data: T }> } | { type: 'snapshot'; seq: number; data: T };

interface UseResyncArgs<T> {
  socket: Socket;
  topic: string;
  onEvent: (seq: number, data: T) => void;
  onSnapshot: (seq: number, data: T) => void;
}

export function useResync<T>({ socket, topic, onEvent, onSnapshot }: UseResyncArgs<T>): void {
  const lastSeqRef = useRef(0);

  useEffect(() => {
    const onDelta = (msg: { seq: number; data: T }): void => {
      if (msg.seq <= lastSeqRef.current) return;
      lastSeqRef.current = msg.seq;
      onEvent(msg.seq, msg.data);
    };

    const onConnect = (): void => {
      socket.emit('resync', { topic, sinceSeq: lastSeqRef.current }, (resp: ResyncResponse<T>) => {
        if (resp.type === 'snapshot') {
          lastSeqRef.current = resp.seq;
          onSnapshot(resp.seq, resp.data);
        } else {
          for (const evt of resp.events) {
            if (evt.seq <= lastSeqRef.current) continue;
            lastSeqRef.current = evt.seq;
            onEvent(evt.seq, evt.data);
          }
        }
      });
    };

    socket.on(`${topic}:event`, onDelta);
    socket.on('connect', onConnect);
    if (socket.connected) onConnect();

    return () => {
      socket.off(`${topic}:event`, onDelta);
      socket.off('connect', onConnect);
    };
  }, [socket, topic, onEvent, onSnapshot]);
}

import { Server, Namespace } from 'socket.io';

export interface ChatHandlers { onJoin(roomId: string, userId: string): void; onMessage(roomId: string, userId: string, text: string): void; }
export interface AdminHandlers { onPurgeRoom(roomId: string, adminId: string): Promise<void>; }

export function mountChatNamespace(io: Server, handlers: ChatHandlers): Namespace {
  const nsp = io.of('/chat');
  nsp.use((socket, next) => {
    if (!(socket.data as { userId?: string }).userId) return next(new Error('UNAUTHENTICATED'));
    next();
  });
  nsp.on('connection', (socket) => {
    const userId = (socket.data as { userId: string }).userId;
    socket.on('chat:join', (roomId: string) => { socket.join(roomId); handlers.onJoin(roomId, userId); });
    socket.on('chat:send', (roomId: string, text: string) => { handlers.onMessage(roomId, userId, text); nsp.to(roomId).emit('chat:message', { roomId, from: userId, text, ts: Date.now() }); });
  });
  return nsp;
}

export function mountAdminNamespace(io: Server, handlers: AdminHandlers): Namespace {
  const nsp = io.of('/admin');
  nsp.use((socket, next) => {
    const data = socket.data as { userId?: string; roles?: string[] };
    if (!data.userId || !data.roles?.includes('admin')) return next(new Error('FORBIDDEN'));
    next();
  });
  nsp.on('connection', (socket) => {
    const adminId = (socket.data as { userId: string }).userId;
    socket.on('admin:purge', async (roomId: string, ack: (ok: boolean) => void) => {
      try { await handlers.onPurgeRoom(roomId, adminId); ack(true); }
      catch { ack(false); }
    });
  });
  return nsp;
}

import { Server, Socket } from 'socket.io';
import { EventEmitter } from 'events';

export interface MetricsSink { gauge(name: string, value: number, labels?: Record<string, string>): void; }

export function instrumentListeners(io: Server, eventBus: EventEmitter, metrics: MetricsSink, intervalMs = 30_000): () => void {
  const interval = setInterval(() => {
    metrics.gauge('socketio.connections', io.engine.clientsCount);
    for (const eventName of eventBus.eventNames()) {
      metrics.gauge('eventbus.listeners', eventBus.listenerCount(eventName), { event: String(eventName) });
    }
  }, intervalMs);
  return () => clearInterval(interval);
}

export function safeBusBinding<T>(socket: Socket, bus: EventEmitter, event: string, handler: (payload: T) => void): void {
  const wrapped = (payload: T): void => handler(payload);
  bus.on(event, wrapped);
  socket.on('disconnect', () => { bus.off(event, wrapped); });
}

import { Server, Socket } from 'socket.io';

interface EditorEvents { onEdit(roomId: string, userId: string, op: { type: 'insert' | 'delete'; pos: number; text?: string; len?: number }): void; }

export function mountEditor(io: Server, events: EditorEvents): void {
  io.on('connection', (socket: Socket) => {
    const userId = (socket.data as { userId: string }).userId;

    socket.on('editor:join', (roomId: string) => { socket.join(roomId); socket.to(roomId).emit('editor:peer-joined', { userId }); });

    socket.on('editor:op', (roomId: string, op: { type: 'insert' | 'delete'; pos: number; text?: string; len?: number }) => {
      events.onEdit(roomId, userId, op);
      socket.to(roomId).emit('editor:op', { userId, op, ts: Date.now() });
    });

    socket.on('disconnecting', () => {
      for (const roomId of socket.rooms) {
        if (roomId === socket.id) continue;
        socket.to(roomId).emit('editor:peer-left', { userId });
      }
    });
  });
}

