export function validated<T>(schema: ZodSchema<T>, handler: (socket: Socket, payload: T) => Promise<void> | void) {
  return async (socket: Socket, raw: unknown, ack?: (res: { ok: boolean; error?: string }) => void): Promise<void> => {
    const parsed = schema.safeParse(raw);
    if (!parsed.success) {
      const err = { ok: false, error: 'VALIDATION_FAILED' };
      if (ack) ack(err); else socket.emit('error', err);
      return;
    }
    try {
      await handler(socket, parsed.data);
      if (ack) ack({ ok: true });
    } catch (e) {
      const err = { ok: false, error: e instanceof Error ? e.message : 'INTERNAL' };
      if (ack) ack(err); else socket.emit('error', err);
    }
  };
}

