import jwt, { JwtPayload, VerifyOptions } from 'jsonwebtoken';
import { readFileSync } from 'fs';

export interface VerifiedToken { userId: string; roles: string[]; exp: number; }

export class TokenVerifier {
  private readonly publicKey: string;
  private readonly options: VerifyOptions;

  constructor(publicKeyPath: string, issuer: string, audience: string) {
    this.publicKey = readFileSync(publicKeyPath, 'utf8');
    this.options = { algorithms: ['RS256'], issuer, audience, clockTolerance: 5 };
  }

  verify(token: string): VerifiedToken {
    const decoded = jwt.verify(token, this.publicKey, this.options) as JwtPayload;
    if (typeof decoded.sub !== 'string') throw new Error('INVALID_SUB');
    if (!Array.isArray((decoded as { roles?: unknown }).roles)) throw new Error('INVALID_ROLES');
    if (typeof decoded.exp !== 'number') throw new Error('INVALID_EXP');
    const roles = (decoded as { roles: unknown[] }).roles.filter((r): r is string => typeof r === 'string');
    return { userId: decoded.sub, roles, exp: decoded.exp };
  }
}

import { lookup } from 'dns/promises';
import net from 'net';
import { fetch as undiciFetch } from 'undici';

function isPrivateIp(ip: string): boolean {
  if (net.isIP(ip) === 4) {
    const parts = ip.split('.').map(Number);
    if (parts[0] === 10) return true;
    if (parts[0] === 127) return true;
    if (parts[0] === 169 && parts[1] === 254) return true;
    if (parts[0] === 172 && parts[1] >= 16 && parts[1] <= 31) return true;
    if (parts[0] === 192 && parts[1] === 168) return true;
    if (parts[0] === 0) return true;
    return false;
  }
  if (net.isIP(ip) === 6) {
    const lower = ip.toLowerCase();
    if (lower === '::1') return true;
    if (lower.startsWith('fc') || lower.startsWith('fd')) return true;
    if (lower.startsWith('fe80')) return true;
    if (lower.startsWith('::ffff:')) return isPrivateIp(lower.slice(7));
    return false;
  }
  return true;
}

export async function safeFetch(rawUrl: string, opts: { maxBytes: number; timeoutMs: number }): Promise<{ status: number; bytes: Buffer; contentType: string | null }> {
  const url = new URL(rawUrl);
  if (url.protocol !== 'http:' && url.protocol !== 'https:') throw new Error('PROTOCOL_FORBIDDEN');
  const resolved = await lookup(url.hostname, { all: false });
  if (isPrivateIp(resolved.address)) throw new Error('PRIVATE_TARGET_FORBIDDEN');

  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), opts.timeoutMs);
  try {
    const res = await undiciFetch(rawUrl, { redirect: 'manual', signal: controller.signal });
    if (res.status >= 300 && res.status < 400) throw new Error('REDIRECT_FORBIDDEN');
    const chunks: Buffer[] = [];
    let total = 0;
    const reader = res.body?.getReader();
    if (!reader) throw new Error('NO_BODY');
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      total += value.byteLength;
      if (total > opts.maxBytes) { controller.abort(); throw new Error('SIZE_LIMIT'); }
      chunks.push(Buffer.from(value));
    }
    return { status: res.status, bytes: Buffer.concat(chunks), contentType: res.headers.get('content-type') };
  } finally { clearTimeout(timeout); }
}

