import { Request, Response } from 'express';
import multer from 'multer';
import sharp from 'sharp';

const ALLOWED_FORMATS = new Set(['jpeg', 'png', 'webp', 'gif']);
const MAX_BYTES = 5 * 1024 * 1024;
const MAX_DIMENSION = 8000;

export const upload = multer({
  storage: multer.memoryStorage(),
  limits: { fileSize: MAX_BYTES, files: 1, fields: 5 },
  fileFilter: (_req, file, cb) => {
    if (!file.mimetype.startsWith('image/')) return cb(new Error('NOT_IMAGE'));
    cb(null, true);
  },
});

export async function handleImageUpload(req: Request, res: Response): Promise<void> {
  const file = req.file;
  if (!file) { res.status(400).json({ error: 'NO_FILE' }); return; }

  let metadata: sharp.Metadata;
  try { metadata = await sharp(file.buffer).metadata(); }
  catch { res.status(400).json({ error: 'INVALID_IMAGE' }); return; }

  if (!metadata.format || !ALLOWED_FORMATS.has(metadata.format)) { res.status(400).json({ error: 'FORMAT_NOT_ALLOWED', format: metadata.format }); return; }
  if (!metadata.width || !metadata.height || metadata.width > MAX_DIMENSION || metadata.height > MAX_DIMENSION) { res.status(400).json({ error: 'DIMENSIONS_TOO_LARGE' }); return; }

  const safe = await sharp(file.buffer).rotate().toFormat(metadata.format === 'gif' ? 'gif' : 'webp', { quality: 85 }).toBuffer();
  res.json({ size: safe.byteLength, format: metadata.format });
}

import argon2 from 'argon2';
import { z } from 'zod';
import { Request, Response } from 'express';
import { UserModel } from './user.model';

const SignupDto = z.object({
  email: z.string().email().max(254).transform((e) => e.toLowerCase()),
  password: z.string().min(12).max(128).regex(/[a-z]/).regex(/[A-Z]/).regex(/[0-9]/),
  name: z.string().min(1).max(80),
});

const ARGON_OPTS: argon2.Options = { type: argon2.argon2id, memoryCost: 65536, timeCost: 3, parallelism: 4 };

export async function signup(req: Request, res: Response): Promise<void> {
  const parsed = SignupDto.safeParse(req.body);
  if (!parsed.success) { res.status(400).json({ errors: parsed.error.flatten() }); return; }
  const { email, password, name } = parsed.data;

  const existing = await UserModel.findOne({ email }).lean();
  if (existing) { res.status(409).json({ error: 'EMAIL_TAKEN' }); return; }

  const passwordHash = await argon2.hash(password, ARGON_OPTS);
  const user = await UserModel.create({ email, name, passwordHash, createdAt: new Date() });
  res.status(201).json({ id: String(user._id), email: user.email });
}

