const HTML_ESCAPES: Record<string, string> = { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' };

export function escapeHtml(input: string): string {
  return input.replace(/[&<>"']/g, (c) => HTML_ESCAPES[c] ?? c);
}

export function escapeAttribute(input: string): string {
  return input.replace(/[&<>"' `=\/]/g, (c) => `&#${c.charCodeAt(0)};`);
}

export function escapeJsString(input: string): string {
  return input.replace(/[\\"']/g, '\\$&').replace(/\u2028/g, '\\u2028').replace(/\u2029/g, '\\u2029').replace(/</g, '\\u003c');
}

