import { useCallback, useEffect, useState } from 'react';

const SAME_TAB_EVENT = 'local-storage-sync';
interface LocalStorageEventDetail { key: string; }

export function useLocalStorage<T>(key: string, initial: T): [T, (value: T | ((prev: T) => T)) => void, () => void] {
  const read = useCallback((): T => {
    if (typeof window === 'undefined') return initial;
    try {
      const raw = window.localStorage.getItem(key);
      return raw === null ? initial : (JSON.parse(raw) as T);
    } catch {
      return initial;
    }
  }, [key, initial]);

  const [value, setValue] = useState<T>(read);

  const notify = useCallback(() => {
    if (typeof window === 'undefined') return;
    window.dispatchEvent(new CustomEvent<LocalStorageEventDetail>(SAME_TAB_EVENT, { detail: { key } }));
  }, [key]);

  const write = useCallback((next: T | ((prev: T) => T)): void => {
    setValue((prev) => {
      const resolved = typeof next === 'function' ? (next as (p: T) => T)(prev) : next;
      if (typeof window !== 'undefined') {
        try { window.localStorage.setItem(key, JSON.stringify(resolved)); } catch { /* quota or disabled storage */ }
        notify();
      }
      return resolved;
    });
  }, [key, notify]);

  const remove = useCallback((): void => {
    if (typeof window !== 'undefined') {
      try { window.localStorage.removeItem(key); } catch { /* disabled storage */ }
      notify();
    }
    setValue(initial);
  }, [key, initial, notify]);

  useEffect(() => {
    if (typeof window === 'undefined') return;
    const onStorage = (event: StorageEvent): void => { if (event.key === key) setValue(read()); };
    const onSameTab = (event: Event): void => {
      const detail = (event as CustomEvent<LocalStorageEventDetail>).detail;
      if (detail?.key === key) setValue(read());
    };
    window.addEventListener('storage', onStorage);
    window.addEventListener(SAME_TAB_EVENT, onSameTab);
    return () => {
      window.removeEventListener('storage', onStorage);
      window.removeEventListener(SAME_TAB_EVENT, onSameTab);
    };
  }, [key, read]);

  return [value, write, remove];
}

import { useMemo, useState } from 'react';

interface Item { id: string; name: string; createdAt: number; priority: number; }

interface ListProps { items: ReadonlyArray<Item>; filter: string; sortBy: keyof Pick<Item, 'name' | 'createdAt' | 'priority'>; }

export function ItemList({ items, filter, sortBy }: ListProps): JSX.Element {
  const filteredSorted = useMemo(() => {
    const needle = filter.trim().toLowerCase();
    const filtered = needle ? items.filter((i) => i.name.toLowerCase().includes(needle)) : items;
    return [...filtered].sort((a, b) => {
      if (sortBy === 'name') return a.name.localeCompare(b.name);
      return (a[sortBy] as number) - (b[sortBy] as number);
    });
  }, [items, filter, sortBy]);

  return (
    <ul>{filteredSorted.map((item) => (<li key={item.id}>{item.name}</li>))}</ul>
  );
}

