import { ChangeEvent, InputHTMLAttributes, useRef, useState, useCallback } from 'react';

type BaseProps = Omit<InputHTMLAttributes<HTMLInputElement>, 'value' | 'defaultValue' | 'onChange'>;

interface ControlledProps<T extends string | number> { value: T; onChange: (next: T) => void; defaultValue?: never; }
interface UncontrolledProps<T extends string | number> { value?: never; onChange?: (next: T) => void; defaultValue?: T; }

export type TextInputProps<T extends string | number = string> = BaseProps & (ControlledProps<T> | UncontrolledProps<T>);

export function TextInput<T extends string | number = string>({ value, defaultValue, onChange, type = 'text', ...rest }: TextInputProps<T>): JSX.Element {
  const isControlledRef = useRef(value !== undefined);
  const [internal, setInternal] = useState<T>((defaultValue ?? '') as T);

  const handleChange = useCallback((e: ChangeEvent<HTMLInputElement>): void => {
    const raw = e.target.value;
    const parsed = (type === 'number' ? Number(raw) : raw) as T;
    if (!isControlledRef.current) setInternal(parsed);
    onChange?.(parsed);
  }, [onChange, type]);

  return <input type={type} value={isControlledRef.current ? (value as T) : internal} onChange={handleChange} {...rest} />;
}

