type ProviderEntry = readonly [ComponentType<{ children: ReactNode } & Record<string, unknown>>, Record<string, unknown>?];

export function composeProviders(providers: ReadonlyArray<ProviderEntry>): FC<{ children: ReactNode }> {
  return ({ children }) =>
    providers.reduceRight<ReactNode>((acc, [Provider, props]) => createElement(Provider, props ?? {}, acc), children) as JSX.Element;
