import { useEffect, useRef, useCallback } from 'react';
import * as THREE from 'three';

interface UsePointerPickerArgs {
  canvas: HTMLCanvasElement | null;
  camera: THREE.Camera | null;
  scene: THREE.Scene | null;
  onPick: (hit: { object: THREE.Object3D; point: THREE.Vector3 } | null, event: PointerEvent) => void;
}

export function usePointerPicker({ canvas, camera, scene, onPick }: UsePointerPickerArgs): void {
  const raycaster = useRef(new THREE.Raycaster());
  const pointer = useRef(new THREE.Vector2());

  const onPointerDown = useCallback((event: PointerEvent): void => {
    if (!canvas || !camera || !scene) return;
    const rect = canvas.getBoundingClientRect();
    pointer.current.x = ((event.clientX - rect.left) / rect.width) * 2 - 1;
    pointer.current.y = -(((event.clientY - rect.top) / rect.height) * 2 - 1);
    raycaster.current.setFromCamera(pointer.current, camera);
    const intersections = raycaster.current.intersectObjects(scene.children, true);
    const first = intersections.find((i) => i.object.userData.pickable !== false) ?? null;
    onPick(first ? { object: first.object, point: first.point } : null, event);
  }, [canvas, camera, scene, onPick]);

  useEffect(() => {
    if (!canvas) return;
    canvas.addEventListener('pointerdown', onPointerDown);
    return () => canvas.removeEventListener('pointerdown', onPointerDown);
  }, [canvas, onPointerDown]);
}

