import { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';

interface SpinningCubeProps { radiansPerSecond: number; orbitRadius: number; orbitSpeed: number; }

export function SpinningCube({ radiansPerSecond, orbitRadius, orbitSpeed }: SpinningCubeProps): JSX.Element {
  const meshRef = useRef<THREE.Mesh>(null);
  const elapsed = useRef(0);

  useFrame((_, delta) => {
    if (!meshRef.current) return;
    const clamped = Math.min(delta, 0.05);
    elapsed.current += clamped;
    meshRef.current.rotation.y += radiansPerSecond * clamped;
    meshRef.current.position.x = Math.cos(elapsed.current * orbitSpeed) * orbitRadius;
    meshRef.current.position.z = Math.sin(elapsed.current * orbitSpeed) * orbitRadius;
  });

  return (
    <mesh ref={meshRef}>
      <boxGeometry args={[1, 1, 1]} />
      <meshStandardMaterial color="hotpink" />
    </mesh>
  );
}

