export type GpuTier = 'low' | 'medium' | 'high';

export function detectGpuTier(gl: WebGLRenderingContext): GpuTier {
  const debugInfo = gl.getExtension('WEBGL_debug_renderer_info');
  if (!debugInfo) return 'medium';
  const renderer = gl.getParameter(debugInfo.UNMASKED_RENDERER_WEBGL) as string;
  const lower = renderer.toLowerCase();
  if (lower.includes('intel') && !lower.includes('iris')) return 'low';
  if (lower.includes('nvidia') || lower.includes('amd radeon')) return 'high';
  return 'medium';
}

export function AdaptivePostprocessing(): JSX.Element | null {
  const { gl } = useThree();
  const [tier, setTier] = useState<GpuTier | null>(null);

  useEffect(() => { setTier(detectGpuTier(gl.getContext())); }, [gl]);

  if (tier === null || tier === 'low') return null;

  return (
    <EffectComposer multisampling={tier === 'high' ? 4 : 0}>
      <Bloom intensity={tier === 'high' ? 1.2 : 0.6} luminanceThreshold={0.85} luminanceSmoothing={0.4} mipmapBlur />
      {tier === 'high' ? <SSAO samples={16} radius={0.3} intensity={20} /> : <></>}
    </EffectComposer>
  );
}

import express, { Request, Response, NextFunction, ErrorRequestHandler } from 'express';
import { NotFoundError, errorMiddleware } from './errors';

export function configureErrorHandling(app: express.Express, logger: { error: (msg: string, ctx: Record<string, unknown>) => void }): void {
  app.use((req: Request, _res: Response, next: NextFunction) => {
    next(new NotFoundError(`Route ${req.method} ${req.path}`));
  });

  app.use(errorMiddleware(logger));
}

