export class TimeoutError extends Error { readonly code = 'TIMEOUT' as const; constructor(public readonly timeoutMs: number) { super(`Operation timed out after ${timeoutMs}ms`); this.name = 'TimeoutError'; } }

export async function fetchWithTimeout(url: string, init: RequestInit & { timeoutMs: number }): Promise<Response> {
  const { timeoutMs, signal: callerSignal, ...rest } = init;
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);

  const onCallerAbort = (): void => controller.abort();
  if (callerSignal) {
    if (callerSignal.aborted) controller.abort();
    else callerSignal.addEventListener('abort', onCallerAbort, { once: true });
  }

  try {
    return await fetch(url, { ...rest, signal: controller.signal });
  } catch (err) {
    if (err instanceof DOMException && err.name === 'AbortError') {
      if (callerSignal?.aborted) throw err;
      throw new TimeoutError(timeoutMs);
    }
    throw err;
  } finally {
    clearTimeout(timer);
    if (callerSignal) callerSignal.removeEventListener('abort', onCallerAbort);
  }
}

import { ClientSession, mongo } from 'mongoose';
import mongoose from 'mongoose';

export interface TxOptions { maxRetries: number; readConcern?: mongo.ReadConcernLevel; writeConcern?: mongo.WriteConcernSettings; }

export async function withTransaction<T>(work: (session: ClientSession) => Promise<T>, opts: TxOptions): Promise<T> {
  let attempt = 0;
  let lastErr: unknown;
  while (attempt < opts.maxRetries) {
    const session = await mongoose.startSession();
    try {
      session.startTransaction({ readConcern: { level: opts.readConcern ?? 'snapshot' }, writeConcern: opts.writeConcern ?? { w: 'majority' } });
      const result = await work(session);
      let commitAttempt = 0;
      while (true) {
        try { await session.commitTransaction(); break; }
        catch (err) {
          if (isUnknownCommitResult(err) && commitAttempt < 3) { commitAttempt++; continue; }
          throw err;
        }
      }
      return result;
    } catch (err) {
      try { await session.abortTransaction(); } catch { /* ignore */ }
      lastErr = err;
      if (!isTransient(err)) throw err;
      attempt++;
      const delay = 50 * 2 ** attempt + Math.random() * 50;
      await new Promise((r) => setTimeout(r, delay));
    } finally {
      await session.endSession();
    }
  }
  throw lastErr;
}

function isTransient(err: unknown): boolean {
  const e = err as { errorLabels?: string[] };
  return Array.isArray(e.errorLabels) && e.errorLabels.includes('TransientTransactionError');
}
function isUnknownCommitResult(err: unknown): boolean {
  const e = err as { errorLabels?: string[] };
  return Array.isArray(e.errorLabels) && e.errorLabels.includes('UnknownTransactionCommitResult');
}

export interface Disposable { dispose(): Promise<void> | void; }
export interface Initializable { init(): Promise<void> | void; }

export type Token<T> = symbol & { __type?: T };
export function token<T>(name: string): Token<T> { return Symbol(name) as Token<T>; }

type Factory<T> = (resolve: <U>(t: Token<U>) => U) => T;

interface Registration<T> { factory: Factory<T>; singleton: boolean; instance?: T; }

export class Container {
  private registrations = new Map<symbol, Registration<unknown>>();
  private lifecycle: Array<unknown> = [];

  register<T>(t: Token<T>, factory: Factory<T>, opts: { singleton?: boolean } = {}): void {
    this.registrations.set(t, { factory: factory as Factory<unknown>, singleton: opts.singleton ?? true });
  }

  resolve<T>(t: Token<T>): T {
    const reg = this.registrations.get(t) as Registration<T> | undefined;
    if (!reg) throw new Error(`No registration for ${t.toString()}`);
    if (reg.singleton && reg.instance !== undefined) return reg.instance;
    const instance = reg.factory((u) => this.resolve(u));
    if (reg.singleton) reg.instance = instance;
    this.lifecycle.push(instance);
    return instance;
  }

  async init(): Promise<void> {
    for (const inst of this.lifecycle) if (isInit(inst)) await inst.init();
  }

  async dispose(): Promise<void> {
    for (const inst of [...this.lifecycle].reverse()) if (isDispose(inst)) await inst.dispose();
  }
}

function isInit(x: unknown): x is Initializable { return typeof (x as Initializable).init === 'function'; }
function isDispose(x: unknown): x is Disposable { return typeof (x as Disposable).dispose === 'function'; }

import { Model, FilterQuery, UpdateQuery, Types } from 'mongoose';

export abstract class BaseRepository<T extends { _id: Types.ObjectId }> {
  constructor(protected readonly model: Model<T>) {}

  async findById(id: string): Promise<T | null> { return this.model.findById(id).lean<T | null>().exec(); }
  async findOne(filter: FilterQuery<T>): Promise<T | null> { return this.model.findOne(filter).lean<T | null>().exec(); }
  async findMany(filter: FilterQuery<T>, limit = 100): Promise<T[]> { return this.model.find(filter).limit(limit).lean<T[]>().exec(); }
  async create(data: Partial<T>): Promise<T> { const doc = await this.model.create(data); return doc.toObject() as T; }
  async updateById(id: string, patch: UpdateQuery<T>): Promise<T | null> { return this.model.findByIdAndUpdate(id, patch, { new: true }).lean<T | null>().exec(); }
  async deleteById(id: string): Promise<boolean> { const r = await this.model.deleteOne({ _id: new Types.ObjectId(id) }); return r.deletedCount === 1; }
}

interface User { _id: Types.ObjectId; email: string; name: string; createdAt: Date; }

export class UserRepository extends BaseRepository<User> {
  async findByEmail(email: string): Promise<User | null> { return this.findOne({ email: email.toLowerCase() }); }
  async existsByEmail(email: string): Promise<boolean> { return (await this.model.exists({ email: email.toLowerCase() })) !== null; }
}

import { Schema, model } from 'mongoose';

interface Order { _id: string; userId: string; status: 'pending' | 'paid' | 'shipped' | 'cancelled'; total: number; createdAt: Date; }

const OrderSchema = new Schema<Order>({
  userId: { type: String, required: true, index: false },
  status: { type: String, required: true, enum: ['pending', 'paid', 'shipped', 'cancelled'] },
  total: Number,
  createdAt: { type: Date, default: Date.now },
});

OrderSchema.index({ userId: 1, status: 1, createdAt: -1 });
OrderSchema.index({ status: 1, createdAt: -1 });

export const OrderModel = model<Order>('Order', OrderSchema);

export interface SearchOpts { userId?: string; status?: Order['status']; createdAfter?: Date; createdBefore?: Date; limit?: number; }

export async function searchOrders(opts: SearchOpts): Promise<Order[]> {
  const filter: Record<string, unknown> = {};
  if (opts.userId) filter.userId = opts.userId;
  if (opts.status) filter.status = opts.status;
  if (opts.createdAfter || opts.createdBefore) {
    filter.createdAt = {};
    if (opts.createdAfter) (filter.createdAt as Record<string, Date>).$gt = opts.createdAfter;
    if (opts.createdBefore) (filter.createdAt as Record<string, Date>).$lt = opts.createdBefore;
  }
  return OrderModel.find(filter).sort({ createdAt: -1 }).limit(opts.limit ?? 50).lean<Order[]>().exec();
}

export async function explainQuery(opts: SearchOpts): Promise<unknown> {
  return OrderModel.find(opts as FilterQuery<Order>).sort({ createdAt: -1 }).explain('executionStats');
}

import { useRef, useCallback, useEffect } from 'react';
import { VariableSizeList, ListChildComponentProps } from 'react-window';
import AutoSizer from 'react-virtualized-auto-sizer';

interface Message { id: string; text: string; from: string; }

interface MessageListProps { messages: ReadonlyArray<Message>; estimatedItemHeight?: number; }

export function MessageList({ messages, estimatedItemHeight = 60 }: MessageListProps): JSX.Element {
  const listRef = useRef<VariableSizeList>(null);
  const sizeMap = useRef<Map<number, number>>(new Map());

  const setSize = useCallback((index: number, size: number): void => {
    const prev = sizeMap.current.get(index);
    if (prev === size) return;
    sizeMap.current.set(index, size);
    listRef.current?.resetAfterIndex(index, true);
  }, []);

  const getSize = useCallback((index: number): number => sizeMap.current.get(index) ?? estimatedItemHeight, [estimatedItemHeight]);

  const Row = useCallback(({ index, style }: ListChildComponentProps): JSX.Element => {
    const rowRef = useRef<HTMLDivElement>(null);
    const message = messages[index];
    useEffect(() => { if (rowRef.current) setSize(index, rowRef.current.getBoundingClientRect().height); }, [index]);
    return (
      <div style={style}>
        <div ref={rowRef} className="px-4 py-2 border-b"><strong>{message.from}:</strong> {message.text}</div>
      </div>
    );
  }, [messages, setSize]);

  return (
    <AutoSizer>{({ height, width }) => (
      <VariableSizeList ref={listRef} height={height} width={width} itemCount={messages.length} itemSize={getSize} overscanCount={5}>
        {Row}
      </VariableSizeList>
    )}</AutoSizer>
  );
}

import type { Redis } from 'ioredis';
import crypto from 'crypto';

const RELEASE_SCRIPT = `if redis.call('GET', KEYS[1]) == ARGV[1] then return redis.call('DEL', KEYS[1]) else return 0 end`;
const EXTEND_SCRIPT = `if redis.call('GET', KEYS[1]) == ARGV[1] then return redis.call('PEXPIRE', KEYS[1], ARGV[2]) else return 0 end`;

export interface LockOptions { key: string; ttlMs: number; renewMs?: number; }

export class DistributedLock {
  private interval: ReturnType<typeof setInterval> | null = null;
  private readonly token = crypto.randomBytes(16).toString('hex');

  constructor(private readonly redis: Redis, private readonly opts: LockOptions) {}

  async acquire(): Promise<boolean> {
    const ok = await this.redis.set(this.opts.key, this.token, 'PX', this.opts.ttlMs, 'NX');
    if (ok !== 'OK') return false;
    const renewMs = this.opts.renewMs ?? Math.floor(this.opts.ttlMs / 3);
    this.interval = setInterval(() => { void this.extend(); }, renewMs);
    return true;
  }

  private async extend(): Promise<void> {
    const r = await this.redis.eval(EXTEND_SCRIPT, 1, this.opts.key, this.token, String(this.opts.ttlMs));
    if (r === 0 && this.interval) { clearInterval(this.interval); this.interval = null; }
  }

  async release(): Promise<void> {
    if (this.interval) { clearInterval(this.interval); this.interval = null; }
    await this.redis.eval(RELEASE_SCRIPT, 1, this.opts.key, this.token);
  }
}

export async function withLock<T>(redis: Redis, key: string, ttlMs: number, work: () => Promise<T>): Promise<T | null> {
  const lock = new DistributedLock(redis, { key, ttlMs });
  if (!await lock.acquire()) return null;
  try { return await work(); }
  finally { await lock.release(); }
}

import { Request, Response, NextFunction } from 'express';
import type { Redis } from 'ioredis';

const PENDING = '__PENDING__';
const TTL_SEC = 3600;

export function idempotencyMiddleware(redis: Redis) {
  return async (req: Request, res: Response, next: NextFunction): Promise<void> => {
    if (req.method === 'GET' || req.method === 'HEAD') return next();
    const key = req.header('Idempotency-Key');
    if (!key) return next();
    if (!/^[0-9a-zA-Z-]{16,128}$/.test(key)) { res.status(400).json({ error: 'INVALID_IDEMPOTENCY_KEY' }); return; }

    const userId = (req as Request & { userId?: string }).userId ?? 'anon';
    const storageKey = `idem:${userId}:${key}`;
    const claimed = await redis.set(storageKey, PENDING, 'EX', TTL_SEC, 'NX');

    if (claimed !== 'OK') {
      const existing = await redis.get(storageKey);
      if (existing === PENDING) { res.status(409).json({ error: 'IN_PROGRESS' }); return; }
      if (existing) { const cached = JSON.parse(existing) as { status: number; body: unknown }; res.status(cached.status).json(cached.body); return; }
      next();
      return;
    }

    const originalJson = res.json.bind(res);
    res.json = ((body: unknown) => {
      void redis.set(storageKey, JSON.stringify({ status: res.statusCode, body }), 'EX', TTL_SEC);
      return originalJson(body);
    }) as typeof res.json;

    next();
  };
}

export type Result<T, E> = { ok: true; value: T } | { ok: false; error: E };

export const ok = <T>(value: T): Result<T, never> => ({ ok: true, value });
export const err = <E>(error: E): Result<never, E> => ({ ok: false, error });

export function map<T, U, E>(r: Result<T, E>, fn: (v: T) => U): Result<U, E> {
  return r.ok ? { ok: true, value: fn(r.value) } : r;
}

export function mapErr<T, E, F>(r: Result<T, E>, fn: (e: E) => F): Result<T, F> {
  return r.ok ? r : { ok: false, error: fn(r.error) };
}

export function andThen<T, U, E>(r: Result<T, E>, fn: (v: T) => Result<U, E>): Result<U, E> {
  return r.ok ? fn(r.value) : r;
}

export function unwrapOr<T, E>(r: Result<T, E>, fallback: T): T {
  return r.ok ? r.value : fallback;
}

export async function fromPromise<T>(p: Promise<T>): Promise<Result<T, Error>> {
  try { return ok(await p); }
  catch (e) { return err(e instanceof Error ? e : new Error(String(e))); }
}

