export type DeepReadonly<T> =
  T extends (...args: never[]) => unknown ? T :
  T extends ReadonlyMap<infer K, infer V> ? ReadonlyMap<DeepReadonly<K>, DeepReadonly<V>> :
  T extends ReadonlySet<infer U> ? ReadonlySet<DeepReadonly<U>> :
  T extends ReadonlyArray<infer U> ? ReadonlyArray<DeepReadonly<U>> :
  T extends object ? { readonly [K in keyof T]: DeepReadonly<T[K]> } :
  T;

export function deepFreeze<T>(value: T): DeepReadonly<T> {
  if (value === null || typeof value !== 'object') return value as DeepReadonly<T>;
  if (Object.isFrozen(value)) return value as DeepReadonly<T>;
  if (value instanceof Map || value instanceof Set) { Object.freeze(value); return value as DeepReadonly<T>; }
  Object.freeze(value);
  for (const key of Object.keys(value)) deepFreeze((value as Record<string, unknown>)[key]);
  return value as DeepReadonly<T>;
}

import type { Socket } from 'socket.io-client';

export class SocketTimeoutError extends Error { constructor() { super('SOCKET_TIMEOUT'); this.name = 'SocketTimeoutError'; } }
export class SocketDisconnectedError extends Error { constructor() { super('SOCKET_DISCONNECTED'); this.name = 'SocketDisconnectedError'; } }

export function emitWithAck<TRes = unknown>(socket: Socket, event: string, payload: unknown, timeoutMs = 5000): Promise<TRes> {
  if (!socket.connected) return Promise.reject(new SocketDisconnectedError());
  return new Promise<TRes>((resolve, reject) => {
    let settled = false;
    const timer = setTimeout(() => {
      if (settled) return;
      settled = true;
      reject(new SocketTimeoutError());
    }, timeoutMs);

    socket.emit(event, payload, (response: TRes) => {
      if (settled) return;
      settled = true;
      clearTimeout(timer);
      resolve(response);
    });
  });
}

import { createServer } from 'http';
import { Server } from 'socket.io';

interface ClientToServer { 'echo': (text: string, ack: (res: { text: string; ts: number }) => void) => void; }
interface ServerToClient { 'broadcast': (msg: { text: string; ts: number }) => void; }

export function start(port: number, allowedOrigins: string[]): void {
  const httpServer = createServer();
  const io = new Server<ClientToServer, ServerToClient>(httpServer, {
    cors: { origin: allowedOrigins, credentials: true },
  });

  io.on('connection', (socket) => {
    socket.on('echo', (text, ack) => {
      const ts = Date.now();
      ack({ text, ts });
    });
  });

  httpServer.listen(port);
}

