}

import { useEffect, useState, useCallback, useRef } from 'react';

interface FetchState<T> { data: T | null; error: Error | null; loading: boolean; }

export function useFetch<T>(url: string, parseJson: (raw: unknown) => T): FetchState<T> & { reload: () => void } {
  const [state, setState] = useState<FetchState<T>>({ data: null, error: null, loading: true });
  const reloadCounter = useRef(0);
  const [trigger, setTrigger] = useState(0);

  const reload = useCallback(() => { reloadCounter.current++; setTrigger((t) => t + 1); }, []);

  useEffect(() => {
    let cancelled = false;
    const controller = new AbortController();
    setState((s) => ({ ...s, loading: true, error: null }));

    fetch(url, { signal: controller.signal })
      .then(async (res) => {
        if (!res.ok) throw new Error(`HTTP_${res.status}`);
        const raw: unknown = await res.json();
        if (cancelled) return;
        setState({ data: parseJson(raw), error: null, loading: false });
      })
      .catch((err: unknown) => {
        if (cancelled || (err instanceof DOMException && err.name === 'AbortError')) return;
        setState({ data: null, error: err instanceof Error ? err : new Error(String(err)), loading: false });
      });

    return () => { cancelled = true; controller.abort(); };
  }, [url, parseJson, trigger]);

  return { ...state, reload };
}

