export type EventMap = Record<string, unknown>;

export class TypedEventBus<E extends EventMap> {
  private handlers = new Map<keyof E, Set<(payload: E[keyof E]) => void | Promise<void>>>();

  on<K extends keyof E>(event: K, handler: (payload: E[K]) => void | Promise<void>): () => void {
    let set = this.handlers.get(event);
    if (!set) { set = new Set(); this.handlers.set(event, set); }
    set.add(handler as (p: E[keyof E]) => void | Promise<void>);
    return () => { set!.delete(handler as (p: E[keyof E]) => void | Promise<void>); };
  }

  async emit<K extends keyof E>(event: K, payload: E[K]): Promise<void> {
    const set = this.handlers.get(event);
    if (!set) return;
    const results = await Promise.allSettled([...set].map((h) => Promise.resolve(h(payload))));
    const failures = results.filter((r): r is PromiseRejectedResult => r.status === 'rejected');
    if (failures.length) console.error(`[bus] ${String(event)} handler errors`, failures.map((f) => f.reason));
  }
}

