import { UserModel } from './user.model';

export interface UserListItem { id: string; email: string; name: string; createdAt: Date; }

export async function listUsers(limit = 50, cursor?: string): Promise<{ items: UserListItem[]; nextCursor: string | null }> {
  const filter: Record<string, unknown> = {};
  if (cursor) filter._id = { $gt: cursor };

  const docs = await UserModel.find(filter)
    .select({ _id: 1, email: 1, name: 1, createdAt: 1 })
    .sort({ _id: 1 })
    .limit(limit)
    .lean<Array<{ _id: { toString(): string }; email: string; name: string; createdAt: Date }>>()
    .exec();

  const items: UserListItem[] = docs.map((d) => ({ id: d._id.toString(), email: d.email, name: d.name, createdAt: d.createdAt }));
  return { items, nextCursor: items.length === limit ? items[items.length - 1].id : null };
}

