import { Types } from 'mongoose';
import { ProductModel } from './product.model';
import { ConflictError, NotFoundError } from '../errors';

export async function reserveStock(productId: string, qty: number): Promise<{ remaining: number }> {
  if (qty <= 0) throw new Error('INVALID_QTY');

  const result = await ProductModel.findOneAndUpdate(
    { _id: new Types.ObjectId(productId), stockQty: { $gte: qty } },
    { $inc: { stockQty: -qty } },
    { new: true, projection: { stockQty: 1 } },
  ).lean<{ stockQty: number } | null>();

  if (result) return { remaining: result.stockQty };

  const exists = await ProductModel.exists({ _id: new Types.ObjectId(productId) });
  if (!exists) throw new NotFoundError('Product');
  throw new ConflictError('Insufficient stock');
}

import { Server, Socket } from 'socket.io';

export interface BinaryChunk { sessionId: string; seq: number; data: Buffer; final: boolean; }

export function mountBinaryStream(io: Server, onChunk: (chunk: BinaryChunk, socket: Socket) => Promise<void>): void {
  io.on('connection', (socket) => {
    const inflightSessions = new Set<string>();

    socket.on('stream:chunk', async (sessionId: string, seq: number, data: Buffer, final: boolean, ack: (ok: boolean) => void) => {
      if (!Buffer.isBuffer(data) || data.byteLength === 0 || data.byteLength > 256 * 1024) { ack(false); return; }
      inflightSessions.add(sessionId);
      try {
        await onChunk({ sessionId, seq, data, final }, socket);
        if (final) inflightSessions.delete(sessionId);
        ack(true);
      } catch { ack(false); }
    });

    socket.on('disconnect', () => { inflightSessions.clear(); });
  });
}

import { io, Socket } from 'socket.io-client';

export interface SocketFactoryArgs { url: string; getToken: () => string | null; }

export function createAuthSocket({ url, getToken }: SocketFactoryArgs): Socket {
  const socket = io(url, {
    autoConnect: false,
    auth: (cb) => { cb({ token: getToken() ?? '' }); },
    reconnection: true,
    reconnectionAttempts: 10,
    reconnectionDelayMax: 5000,
  });

  socket.on('connect_error', (err) => {
    if (err.message === 'UNAUTHENTICATED' || err.message === 'INVALID_TOKEN') {
      socket.disconnect();
    }
  });

  socket.connect();
  return socket;
}

import crypto from 'crypto';

function hotp(secret: Buffer, counter: number, digits = 6): string {
  const buf = Buffer.alloc(8);
  buf.writeBigUInt64BE(BigInt(counter));
  const hmac = crypto.createHmac('sha1', secret).update(buf).digest();
  const offset = hmac[hmac.length - 1] & 0xf;
  const code = ((hmac[offset] & 0x7f) << 24) | ((hmac[offset + 1] & 0xff) << 16) | ((hmac[offset + 2] & 0xff) << 8) | (hmac[offset + 3] & 0xff);
  return (code % 10 ** digits).toString().padStart(digits, '0');
}

export function verifyTotp(secretBase32: string, token: string, window = 1, stepSec = 30): boolean {
  if (!/^\d{6}$/.test(token)) return false;
  const secret = base32Decode(secretBase32);
  const counter = Math.floor(Date.now() / 1000 / stepSec);
  const tokenBuf = Buffer.from(token);
  for (let i = -window; i <= window; i++) {
    const candidate = hotp(secret, counter + i);
    const candidateBuf = Buffer.from(candidate);
    if (candidateBuf.length === tokenBuf.length && crypto.timingSafeEqual(candidateBuf, tokenBuf)) return true;
  }
  return false;
}

function base32Decode(s: string): Buffer {
  const alphabet = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ234567';
  const clean = s.replace(/=+$/, '').toUpperCase();
  const bits: number[] = [];
  for (const ch of clean) {
    const v = alphabet.indexOf(ch);
    if (v < 0) throw new Error('INVALID_BASE32');
    for (let i = 4; i >= 0; i--) bits.push((v >> i) & 1);
  }
  const bytes: number[] = [];
  for (let i = 0; i + 8 <= bits.length; i += 8) {
    let b = 0;
    for (let j = 0; j < 8; j++) b = (b << 1) | bits[i + j];
    bytes.push(b);
  }
  return Buffer.from(bytes);
}

