import { useReducer, useCallback } from 'react';

interface HistoryState<T> { past: T[]; present: T; future: T[]; }

type HistoryAction<A> = { type: 'UNDO' } | { type: 'REDO' } | { type: 'DO'; action: A };

export function useHistoryReducer<T, A>(
  reducer: (state: T, action: A) => T,
  initial: T,
  maxHistory = 50,
): { state: T; dispatch: (action: A) => void; undo: () => void; redo: () => void; canUndo: boolean; canRedo: boolean } {
  function historyReducer(state: HistoryState<T>, action: HistoryAction<A>): HistoryState<T> {
    switch (action.type) {
      case 'UNDO': {
        if (state.past.length === 0) return state;
        const newPresent = state.past[state.past.length - 1];
        return { past: state.past.slice(0, -1), present: newPresent, future: [state.present, ...state.future] };
      }
      case 'REDO': {
        if (state.future.length === 0) return state;
        const newPresent = state.future[0];
        return { past: [...state.past, state.present], present: newPresent, future: state.future.slice(1) };
      }
      case 'DO': {
        const next = reducer(state.present, action.action);
        if (Object.is(next, state.present)) return state;
        const newPast = [...state.past, state.present];
        if (newPast.length > maxHistory) newPast.shift();
        return { past: newPast, present: next, future: [] };
      }
    }
  }

  const [state, raw] = useReducer(historyReducer, { past: [], present: initial, future: [] });
  const dispatch = useCallback((action: A) => raw({ type: 'DO', action }), []);
  const undo = useCallback(() => raw({ type: 'UNDO' }), []);
  const redo = useCallback(() => raw({ type: 'REDO' }), []);

  return { state: state.present, dispatch, undo, redo, canUndo: state.past.length > 0, canRedo: state.future.length > 0 };
}

