interface Logger { error(msg: string, ctx: Record<string, unknown>): void; }

export function installProcessErrorHandlers(logger: Logger, shutdown: () => Promise<void>): void {
  let shuttingDown = false;

  const fatal = (kind: 'uncaughtException' | 'unhandledRejection', err: unknown): void => {
    if (shuttingDown) return;
    shuttingDown = true;
    const e = err instanceof Error ? err : new Error(String(err));
    logger.error(`[fatal] ${kind}`, { name: e.name, message: e.message, stack: e.stack });
    const timeout = setTimeout(() => process.exit(1), 5000).unref();
    shutdown().finally(() => { clearTimeout(timeout); process.exit(1); });
  };

  process.on('uncaughtException', (err) => fatal('uncaughtException', err));
  process.on('unhandledRejection', (err) => fatal('unhandledRejection', err));
}

