const pipelineAsync = promisify(pipeline);

function csvEscape(value: unknown): string {
  const s = value === null || value === undefined ? '' : String(value);
  return /[",\n\r]/.test(s) ? `"${s.replace(/"/g, '""')}"` : s;
}

export async function exportUsersCsv(_req: Request, res: Response): Promise<void> {
  res.setHeader('Content-Type', 'text/csv; charset=utf-8');
  res.setHeader('Content-Disposition', 'attachment; filename="users.csv"');
  res.write('id,email,name,createdAt\n');

  const cursor = UserModel.find({}).select({ _id: 1, email: 1, name: 1, createdAt: 1 }).lean().cursor();

  const transform = new Transform({
    objectMode: true,
    transform(doc: { _id: { toString(): string }; email: string; name: string; createdAt: Date }, _enc, cb) {
      const row = [doc._id.toString(), doc.email, doc.name, doc.createdAt.toISOString()].map(csvEscape).join(',') + '\n';
      cb(null, row);
    },
  });

  try { await pipelineAsync(cursor, transform, res); }
  catch (err) { if (!res.headersSent) res.status(500).end(); else res.destroy(err as Error); }
}

