export interface SocketMetrics { gauge(name: string, value: number): void; increment(name: string, labels?: Record<string, string>): void; }

export function instrumentIO(io: Server, metrics: SocketMetrics): void {
  setInterval(() => metrics.gauge('socket.connections', io.engine.clientsCount), 10_000);

  io.on('connection', (socket: Socket) => {
    const connectedAt = Date.now();
    const userId = (socket.data as { userId?: string }).userId;
    logWithContext('info', 'socket.connected', { socketId: socket.id, userId, transport: socket.conn.transport.name });
    metrics.increment('socket.connected');

    const originalOn = socket.on.bind(socket);
    socket.on = ((event: string, handler: (...args: unknown[]) => void) => {
      return originalOn(event, (...args: unknown[]) => {
        metrics.increment('socket.event', { event });
        return handler(...args);
      });
    }) as typeof socket.on;

    socket.on('disconnect', (reason) => {
      const durationMs = Date.now() - connectedAt;
      logWithContext('info', 'socket.disconnected', { socketId: socket.id, userId, reason, durationMs });
      metrics.increment('socket.disconnected', { reason });
    });
  });
}

import crypto from 'crypto';
import express, { Request, Response, NextFunction } from 'express';

const TOLERANCE_SEC = 300;

export function rawJsonBody() { return express.raw({ type: 'application/json' }); }

export function verifyWebhook(secret: string) {
  return (req: Request, res: Response, next: NextFunction): void => {
    const header = req.header('X-Signature');
    if (!header) { res.status(400).json({ error: 'NO_SIGNATURE' }); return; }

    const match = header.match(/^t=(\d+),v1=([0-9a-f]{64})$/);
    if (!match) { res.status(400).json({ error: 'BAD_SIGNATURE_FORMAT' }); return; }
    const ts = Number(match[1]);
    const signature = match[2];

    if (Math.abs(Date.now() / 1000 - ts) > TOLERANCE_SEC) { res.status(400).json({ error: 'EXPIRED' }); return; }

    const body = req.body as Buffer;
    const payload = `${ts}.${body.toString('utf8')}`;
    const expected = crypto.createHmac('sha256', secret).update(payload).digest('hex');
    const expectedBuf = Buffer.from(expected, 'hex');
    const signatureBuf = Buffer.from(signature, 'hex');
    if (expectedBuf.length !== signatureBuf.length || !crypto.timingSafeEqual(expectedBuf, signatureBuf)) {
      res.status(400).json({ error: 'INVALID_SIGNATURE' });
      return;
    }

    try { (req as Request & { webhookBody: unknown }).webhookBody = JSON.parse(body.toString('utf8')); }
    catch { res.status(400).json({ error: 'INVALID_JSON' }); return; }
    next();
  };
}

