export interface Job<T> { id: string; payload: T; }
export interface JobHandler<T> { (job: Job<T>): Promise<void>; }

export class AsyncQueue<T> {
  private pending: Job<T>[] = [];
  private inFlight = 0;
  private draining = false;
  private resolveDrain: (() => void) | null = null;

  constructor(private readonly handler: JobHandler<T>, private readonly concurrency: number) {}

  push(job: Job<T>): void {
    if (this.draining) throw new Error('QUEUE_DRAINING');
    this.pending.push(job);
    this.tick();
  }

  private tick(): void {
    while (this.inFlight < this.concurrency && this.pending.length > 0) {
      const job = this.pending.shift()!;
      this.inFlight++;
      this.handler(job)
        .catch((err) => console.error(`[queue] job ${job.id} failed`, err))
        .finally(() => {
          this.inFlight--;
          if (this.draining && this.inFlight === 0 && this.pending.length === 0) this.resolveDrain?.();
          else this.tick();
        });
    }
  }

  async drain(timeoutMs: number): Promise<void> {
    this.draining = true;
    if (this.inFlight === 0 && this.pending.length === 0) return;
    return new Promise<void>((resolve) => {
      this.resolveDrain = resolve;
      setTimeout(() => resolve(), timeoutMs).unref();
    });
  }
}

type ParamName<S extends string> = S extends `${infer Name}/${string}` ? Name : S;

type ExtractParams<Path extends string> =
