interface HeartbeatOpts { intervalMs: number; timeoutMs: number; }

export function attachHeartbeat(io: Server, opts: HeartbeatOpts): void {
  io.on('connection', (socket: Socket) => {
    let timer: ReturnType<typeof setInterval> | null = null;
    let lastPong = Date.now();

    socket.on('app:pong', () => { lastPong = Date.now(); });

    timer = setInterval(() => {
      const stale = Date.now() - lastPong;
      if (stale > opts.timeoutMs) {
        socket.disconnect(true);
        return;
      }
      socket.emit('app:ping');
    }, opts.intervalMs);

    socket.on('disconnect', () => { if (timer) clearInterval(timer); });
  });
}

