    previousFocus.current = document.activeElement as HTMLElement | null;
    const previousOverflow = document.body.style.overflow;
    document.body.style.overflow = 'hidden';

    const panel = panelRef.current;
    const first = panel?.querySelector<HTMLElement>(FOCUSABLE);
    (first ?? panel)?.focus();

    const onKey = (event: KeyboardEvent): void => {
      if (event.key === 'Escape') { onClose(); return; }
      if (event.key !== 'Tab' || !panel) return;
      const nodes = [...panel.querySelectorAll<HTMLElement>(FOCUSABLE)];
      if (nodes.length === 0) { event.preventDefault(); return; }
      const firstNode = nodes[0];
      const lastNode = nodes[nodes.length - 1];
      if (event.shiftKey && document.activeElement === firstNode) { event.preventDefault(); lastNode.focus(); }
      else if (!event.shiftKey && document.activeElement === lastNode) { event.preventDefault(); firstNode.focus(); }
    };

    document.addEventListener('keydown', onKey);
    return () => {
      document.removeEventListener('keydown', onKey);
      document.body.style.overflow = previousOverflow;
      previousFocus.current?.focus();
    };
  }, [open, onClose]);

  if (!open) return null;
  return createPortal(
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center" onMouseDown={onClose}>
      <div ref={panelRef} tabIndex={-1} role="dialog" aria-modal="true" aria-labelledby={titleId} className="bg-white rounded-lg p-6 max-w-md w-full" onMouseDown={(e) => e.stopPropagation()}>
        <h2 id={titleId}>{title}</h2>
        {children}
        <button type="button" onClick={onClose}>Close</button>
      </div>
    </div>,
    document.body,
  );
}

import { useState, useCallback, useEffect } from 'react';

interface State<T> { data: T | null; error: Error | null; loading: boolean; }

interface FriendlyFetcherProps<T> { fetcher: () => Promise<T>; render: (data: T) => JSX.Element; emptyMessage?: string; }

export function FriendlyFetcher<T>({ fetcher, render, emptyMessage = 'No data' }: FriendlyFetcherProps<T>): JSX.Element {
  const [state, setState] = useState<State<T>>({ data: null, error: null, loading: true });
  const [attempt, setAttempt] = useState(0);

  const run = useCallback(async () => {
    setState((s) => ({ ...s, error: null, loading: true }));
    try { const data = await fetcher(); setState({ data, error: null, loading: false }); }
    catch (e) { setState((s) => ({ data: s.data, error: e instanceof Error ? e : new Error(String(e)), loading: false })); }
  }, [fetcher]);

  useEffect(() => { void run(); }, [run, attempt]);

  if (state.loading && !state.data) return <div className="p-8 text-gray-500">Loading…</div>;
  if (state.error && !state.data) return (
    <div className="p-8 text-red-700 bg-red-50 rounded">
      <p>Something went wrong: {state.error.message}</p>
      <button onClick={() => setAttempt((a) => a + 1)} className="mt-2 px-4 py-1 bg-red-600 text-white rounded">Retry</button>
    </div>
  );
  if (!state.data) return <div className="p-8 text-gray-500">{emptyMessage}</div>;
  return (
    <div>
      {state.error && (
        <div className="p-2 mb-2 bg-yellow-50 text-yellow-800 text-sm flex justify-between">
          <span>Failed to refresh — showing previous data.</span>
          <button onClick={() => setAttempt((a) => a + 1)} className="underline">Retry</button>
        </div>
      )}
      {render(state.data)}
    </div>
  );
}

export interface User { id: string; email: string; name: string; status: 'active' | 'suspended'; }

export interface UserLookup {
  findById(id: string): Promise<User | null>;
  existsAndActive(id: string): Promise<boolean>;
}

export interface UserRepository extends UserLookup {
  create(input: Omit<User, 'id'>): Promise<User>;
  updateProfile(id: string, patch: Partial<Pick<User, 'name' | 'email'>>): Promise<User | null>;
  suspend(id: string): Promise<boolean>;
}

import { ForbiddenError, NotFoundError } from '../errors';

export class OrderService {
  constructor(private readonly users: UserLookup) {}

  async ensureActive(userId: string): Promise<User> {
    const user = await this.users.findById(userId);
    if (!user) throw new NotFoundError('User');
    if (user.status !== 'active') throw new ForbiddenError('User suspended');
    return user;
  }
}

import { Model } from 'mongoose';

export interface UpsertOp<T> { filter: Partial<T>; update: Partial<T>; }

export async function bulkUpsert<T>(model: Model<T>, ops: ReadonlyArray<UpsertOp<T>>, chunkSize = 1000): Promise<{ matched: number; upserted: number; modified: number }> {
  let matched = 0, upserted = 0, modified = 0;
  for (let i = 0; i < ops.length; i += chunkSize) {
    const chunk = ops.slice(i, i + chunkSize);
    const writes = chunk.map(({ filter, update }) => ({ updateOne: { filter, update: { $set: update }, upsert: true } }));
    const result = await model.bulkWrite(writes, { ordered: false });
    matched += result.matchedCount;
    upserted += Object.keys(result.upsertedIds ?? {}).length;
    modified += result.modifiedCount;
  }
  return { matched, upserted, modified };
}

export interface DebounceOptions { waitMs: number; leading?: boolean; trailing?: boolean; }

export function debounce<A extends unknown[]>(fn: (...args: A) => void, opts: DebounceOptions): { call: (...args: A) => void; flush: () => void; cancel: () => void } {
  const { waitMs, leading = false, trailing = true } = opts;
  let timer: ReturnType<typeof setTimeout> | null = null;
  let lastArgs: A | null = null;

  const invoke = (): void => { if (lastArgs) { fn(...lastArgs); lastArgs = null; } };

  const call = (...args: A): void => {
    lastArgs = args;
    const shouldFireLeading = leading && timer === null;
    if (timer) clearTimeout(timer);
    timer = setTimeout(() => { timer = null; if (trailing) invoke(); else lastArgs = null; }, waitMs);
    if (shouldFireLeading) { fn(...args); lastArgs = null; }
  };

  const flush = (): void => { if (timer) { clearTimeout(timer); timer = null; invoke(); } };
  const cancel = (): void => { if (timer) { clearTimeout(timer); timer = null; } lastArgs = null; };

  return { call, flush, cancel };
}

import { Server, Socket } from 'socket.io';
import type { Redis } from 'ioredis';

interface SubmitPayload {
  requestId: string;
  order: { sku: string; quantity: number };
}

type SubmitResult = { ok: true; orderId: string; duplicate?: boolean } | { ok: false; code: string };

const TTL_SECONDS = 10 * 60;

function idemKey(userId: string, requestId: string): string {
  return `idem:order-submit:${userId}:${requestId}`;
}

export function attachSubmitHandler(io: Server, redis: Redis): void {
  io.on('connection', (socket: Socket) => {
    const userId = (socket.data as { userId?: string }).userId;
    if (!userId) return;

    socket.on('order:submit', async (payload: SubmitPayload, ack?: (res: SubmitResult) => void) => {
      if (!payload?.requestId || typeof payload.requestId !== 'string') {
        ack?.({ ok: false, code: 'MISSING_REQUEST_ID' });
        return;
      }

      const key = idemKey(userId, payload.requestId);
      const existing = await redis.get(key);
      if (existing) {
        ack?.({ ...(JSON.parse(existing) as SubmitResult), duplicate: true });
        return;
      }

      const lockKey = `${key}:lock`;
      const locked = await redis.set(lockKey, '1', 'EX', 30, 'NX');
      if (!locked) {
        ack?.({ ok: false, code: 'DUPLICATE_IN_PROGRESS' });
        return;
      }

      try {
        const orderId = await createOrderAtomic(userId, payload.order, payload.requestId);
        const result: SubmitResult = { ok: true, orderId };
        await redis.set(key, JSON.stringify(result), 'EX', TTL_SECONDS);
        ack?.(result);
      } catch {
        ack?.({ ok: false, code: 'ORDER_CREATE_FAILED' });
      } finally {
        await redis.del(lockKey);
      }
    });
  });
}

async function createOrderAtomic(_userId: string, _order: { sku: string; quantity: number }, _requestId: string): Promise<string> {
  // Also enforce UNIQUE(user_id, request_id) in the orders table.
  return 'ord_123';
}

import type { Redis } from 'ioredis';
import { Server, Socket } from 'socket.io';

const HEARTBEAT_MS = 8_000;
const STALE_MS = 30_000;

interface PresenceAuth { tenantId: string; userId: string; }

function tenantUsersKey(tenantId: string): string { return `presence:${tenantId}:users`; }
function userSocketsKey(tenantId: string, userId: string): string { return `presence:${tenantId}:user:${userId}:sockets`; }

async function touch(redis: Redis, tenantId: string, userId: string, socketId: string): Promise<void> {
  const now = Date.now();
  await redis.pipeline()
    .zadd(tenantUsersKey(tenantId), now, userId)
    .zadd(userSocketsKey(tenantId, userId), now, socketId)
    .pexpire(userSocketsKey(tenantId, userId), STALE_MS * 2)
    .exec();
}

async function prune(redis: Redis, tenantId: string, userId?: string): Promise<void> {
  const cutoff = Date.now() - STALE_MS;
  await redis.zremrangebyscore(tenantUsersKey(tenantId), 0, cutoff);
  if (userId) await redis.zremrangebyscore(userSocketsKey(tenantId, userId), 0, cutoff);
}

export function setupPresence(io: Server, redis: Redis): void {
  io.on('connection', (socket: Socket) => {
    const auth = socket.handshake.auth as Partial<PresenceAuth>;
    if (!auth.tenantId || !auth.userId) {
      socket.disconnect(true);
      return;
    }

    const { tenantId, userId } = auth as PresenceAuth;
    void touch(redis, tenantId, userId, socket.id);

    const pulse = setInterval(() => {
      void touch(redis, tenantId, userId, socket.id);
    }, HEARTBEAT_MS);

    socket.on('presence:list', async (ack?: (users: string[]) => void) => {
      await prune(redis, tenantId);
      const users = await redis.zrangebyscore(tenantUsersKey(tenantId), Date.now() - STALE_MS, '+inf');
      ack?.(users);
    });

    socket.on('disconnect', async () => {
      clearInterval(pulse);
      await redis.zrem(userSocketsKey(tenantId, userId), socket.id);
      await prune(redis, tenantId, userId);
      const remaining = await redis.zcard(userSocketsKey(tenantId, userId));
      if (remaining === 0) await redis.zrem(tenantUsersKey(tenantId), userId);
    });
  });
}

import type { Redis } from 'ioredis';
import { Server } from 'socket.io';

interface ChatEvent { roomId: string; body: string; clientMsgId: string; }
interface StoredEvent extends ChatEvent { seq: number; at: number; }

export function setupOrderedRoomEmitter(io: Server, redis: Redis): void {
  io.on('connection', (socket) => {
    socket.on('chat:send', async ({ roomId, body, clientMsgId }: ChatEvent, ack?: (res: { ok: boolean; seq?: number }) => void) => {
      const seq = await redis.incr(`room:${roomId}:seq`);
      const event: StoredEvent = { roomId, body, clientMsgId, seq, at: Date.now() };
      await redis.zadd(`room:${roomId}:log`, seq, JSON.stringify(event));
      await redis.zremrangebyrank(`room:${roomId}:log`, 0, -501);
      io.to(roomId).emit('chat:message', event);
      ack?.({ ok: true, seq });
    });

    socket.on('chat:request_sync', async ({ roomId, fromSeq }: { roomId: string; fromSeq: number }, ack?: (events: StoredEvent[]) => void) => {
      const raw = await redis.zrangebyscore(`room:${roomId}:log`, fromSeq + 1, '+inf', 'LIMIT', 0, 50);
      ack?.(raw.map((x) => JSON.parse(x) as StoredEvent));
    });
  });
}

import { Server, Socket } from 'socket.io';
import crypto from 'crypto';

const ALLOWED_ORIGINS = new Set((process.env.ALLOWED_ORIGINS ?? '').split(',').map((o) => o.trim()).filter(Boolean));
const CSRF_WINDOW_MS = 2 * 60_000;
const CSRF_SECRET = process.env.CSRF_SECRET;

function sign(userId: string, bucket: number): string {
  if (!CSRF_SECRET) throw new Error('CSRF_SECRET is required');
  return crypto.createHmac('sha256', CSRF_SECRET).update(`${userId}:${bucket}`).digest('hex');
}

function timingSafeEqualHex(a: string, b: string): boolean {
  const ab = Buffer.from(a, 'hex');
  const bb = Buffer.from(b, 'hex');
  return ab.length === bb.length && crypto.timingSafeEqual(ab, bb);
}

function verifyHandshakeToken(userId: string, token: string): boolean {
  const [bucketText, mac] = token.split('.');
  const bucket = Number(bucketText);
  if (!Number.isInteger(bucket) || !mac) return false;
  const current = Math.floor(Date.now() / CSRF_WINDOW_MS);
  if (bucket < current - 1 || bucket > current) return false;
  return timingSafeEqualHex(mac, sign(userId, bucket));
}

export function secureSocketHandshake(io: Server): void {
  io.use((socket: Socket, next) => {
    const origin = socket.handshake.headers.origin;
    if (!origin || !ALLOWED_ORIGINS.has(origin)) return next(new Error('INVALID_ORIGIN'));

    const auth = socket.handshake.auth as { userId?: string; csrfToken?: string };
    if (!auth.userId || !auth.csrfToken || !verifyHandshakeToken(auth.userId, auth.csrfToken)) {
      return next(new Error('INVALID_CSRF'));
    }

    next();
  });
}

export function generateHandshakeToken(userId: string): string {
  const bucket = Math.floor(Date.now() / CSRF_WINDOW_MS);
  return `${bucket}.${sign(userId, bucket)}`;
}

import { Server, Socket } from 'socket.io';
import { z } from 'zod';

const DANGEROUS_KEYS = new Set(['__proto__', 'prototype', 'constructor']);
const MetadataValue = z.union([z.string(), z.number(), z.boolean(), z.null()]);
const MessageSchema = z.object({
  channelId: z.string().min(1),
  text: z.string().trim().min(1).max(2000),
  metadata: z.record(MetadataValue).optional(),
}).strict();

function safeMetadata(input: Record<string, z.infer<typeof MetadataValue>> | undefined): Record<string, string | number | boolean | null> | undefined {
  if (!input) return undefined;
  const out: Record<string, string | number | boolean | null> = Object.create(null);
  for (const [key, value] of Object.entries(input)) {
    if (DANGEROUS_KEYS.has(key)) throw new Error('DANGEROUS_METADATA_KEY');
    out[key] = value;
  }
  return out;
}

export function attachChat(io: Server): void {
  io.on('connection', (socket: Socket) => {
    socket.on('chat:send', async (raw: unknown, ack?: (ok: boolean) => void) => {
      const parsed = MessageSchema.safeParse(raw);
      if (!parsed.success) {
        socket.emit('chat:error', { code: 'INVALID_PAYLOAD', issues: parsed.error.issues });
        ack?.(false);
        return;
      }

      try {
        const message = {
          channelId: parsed.data.channelId,
          text: parsed.data.text,
          metadata: safeMetadata(parsed.data.metadata),
        };
        await persistMessage(message);
        io.to(message.channelId).emit('chat:created', message);
        ack?.(true);
      } catch {
        socket.emit('chat:error', { code: 'INVALID_METADATA' });
        ack?.(false);
      }
    });
  });
}

async function persistMessage(_message: { channelId: string; text: string; metadata?: Record<string, string | number | boolean | null> }): Promise<void> {
  await Promise.resolve();
}
